# Maximum depth of the explicit render stack in ``_render_iterall`` (t-call
# nesting). Exceeding it signals unbounded recursion (e.g. a template that
# t-calls itself) rather than a legitimately deep page, and aborts with a
# RecursionError instead of exhausting memory.
QWEB_MAX_RENDER_DEPTH = 50

ETREE_TEMPLATE_REF = count()

# Only allow a javascript scheme if it is followed by [ ][window.]history.back()
MALICIOUS_SCHEMES = re.compile(
    r"javascript:(?!( ?)((window\.)?)history\.back\(\)$)", re.IGNORECASE
).findall
# C0 control characters (incl. TAB, LF, CR, NUL) are removed from a URL by the
# browser before the scheme is resolved, so ``java&#9;script:`` style payloads
# collapse to ``javascript:`` and execute. Strip them before the
# MALICIOUS_SCHEMES match so those obfuscations are still caught. Stripping only
# adds detections (the cleaned form is matched, never the stored value), so
# legitimate URLs are unaffected.
URL_CONTROL_CHARS = re.compile(r"[\x00-\x1f]")


def _id_or_xmlid(ref: str | int) -> str | int:
    try:
        return int(ref)
    except ValueError:
        return ref


def indent_code(code: str, level: int) -> str:
    """Indent the code to respect the python syntax."""
    return textwrap.indent(textwrap.dedent(code).strip(), " " * 4 * level)


def _group_caches_by_prefix(caches: Mapping[str, Any]) -> dict[str, list]:
    """Group cache objects by the prefix before the first dot in their name.

    A module-level helper rather than a class-body loop: building this inside a
    ``class`` block with a bare ``for`` leaks the loop variables as class
    attributes, and a comprehension can't see the class-level cache dict (class
    scope is not visible to nested comprehensions).
    """
    groups: dict[str, list] = {}
    for name, cache in caches.items():
        groups.setdefault(name.split(".")[0], []).append(cache)
    return groups


class QwebCallParameters(NamedTuple):
    context: dict[str, Any]
    view_ref: str | int
    method: str | None
    values: dict[str, Any] | None
    scope: bool | Literal["root"]
    directive: str
    path_xml: tuple[str | int, str, str] | None

    def __repr__(self) -> str:
        # cleaning context and values in order to have a consistent log when debugging.
        context = {k: v for k, v in self.context.items() if not k.startswith("_")}
        qweb_root_values = self.values.get("__qweb_root_values") or {}
        values = self.values and {
            k: v
            for k, v in self.values.items()
            if k not in ("__qweb_root_values", "__qweb_attrs__")
            if v is not qweb_root_values.get(k)
        }
        return (
            f"<QwebCallParameters context={context!r} view_ref={self.view_ref!r}"
            f" method={self.method!r} values={values!r} scope={self.scope!r}"
            f" directive={self.directive!r} path_xml={self.path_xml!r}>"
        )


class QwebStackFrame(NamedTuple):
    params: QwebCallParameters | QwebContent
    irQweb: IrQweb
    iterator: Iterator[str | QwebCallParameters | QwebContent]
    values: dict[str, Any]
    options: dict[str, Any] | None

    def __repr__(self) -> str:
        return f"<QwebStackFrame {self.params!r}>"


class QwebContent:
    """QwebContent wraps a snippet to be used as a string value or a fragment.
    If the value is used with a string operation (from a qweb directive
    like `t-att-help="value % 1"`), the QwebContent loads the snippet.
    If the value is inserted in the document (`t-out="value"`), the snippet
    params bubble up to `_render_iterall`.
    """

    irQweb: IrQweb
    html: str | None
    params__: (
        QwebCallParameters  # not available for the python expression inside the xml
    )

    def __init__(self, irQweb: IrQweb, params: QwebCallParameters) -> None:
        self.irQweb = irQweb
        self.html = None
        self.params__ = params

    def __str__(self) -> str:
        if self.html is None:
            params = self.params__
            self.html = "".join(
                self.irQweb._render_iterall(
                    params.view_ref,
                    params.method,
                    params.values,
                    params.directive,
                )
            )
        return self.html

    def __repr__(self) -> str:
        return f"<QwebContent {self.params__!r}>"

    def __len__(self) -> int:
        return len(str(self))

    def __html__(self) -> str:
        return self.__str__()

    def __contains__(self, key: str) -> bool:
        return key in Markup(self)

    def __getattr__(self, name: str) -> Any:
        return getattr(Markup(self), name)

    def __getitem__(self, key: int | slice) -> Any:
        return Markup(self)[key]

    def __add__(self, other: Any) -> Markup:
        return Markup(self).__add__(other)

    def __radd__(self, other: Any) -> Markup:
        return Markup(self).__radd__(other)

    def __mod__(self, other: Any) -> Markup:
        return Markup(self).__mod__(other)

    def __rmod__(self, other: Any) -> Markup:
        return Markup(self).__rmod__(other)


class QwebJSON(json.JSON):
    def dumps(self, *args: Any, **kwargs: Any) -> str:
        prev_default = kwargs.pop("default", lambda obj: obj)
        return super().dumps(
            *args,
            **kwargs,
            default=(
                lambda obj: prev_default(
                    str(obj) if isinstance(obj, QwebContent) else obj
                )
            ),
        )


qwebJSON = QwebJSON()


class _EsmFallbackError(Exception):
    """Internal control-flow signal: a production native-ESM render declined
    (esbuild circuit open, lock contention, or build failure). Raised by
    ``IrQweb._get_native_module_nodes_cached`` so the ``assets`` ormcache never
    stores the degraded debug-mode fallback (ormcache does not cache
    exceptions); caught by ``_get_native_module_nodes``, which then renders the
    fallback uncached.
    """


class IrQweb(models.AbstractModel):
    """Base QWeb rendering engine
    * to customize ``t-field`` rendering, subclass ``ir.qweb.field`` and
      create new models called :samp:`ir.qweb.field.{widget}`
    Beware that if you need extensions or alterations which could be
    incompatible with other subsystems, you should create a local object
    inheriting from ``ir.qweb`` and customize that.
    """

    _name = "ir.qweb"
    _description = "Qweb"

    @api.model
    def _render(
        self,
        template: int | str | etree._Element,
        values: dict[str, Any] | None = None,
        **options: Any,
    ) -> Markup:
        """Render the template specified by the given name.

        :param template: etree, xml_id, template name (see _get_template)
            * Call the method ``load`` is not an etree.
        :param dict values: template values to be used for rendering
        :param options: used to compile the template
            Options will be add into the IrQweb.env.context for the rendering.

            * ``lang`` (str) used language to render the template
            * ``inherit_branding`` (bool) add the tag node branding
            * ``inherit_branding_auto`` (bool) add the branding on fields
            * ``minimal_qcontext``(bool) To use the minimum context and options
              from ``_prepare_environment``

        :return: the rendered template, markup-safe
        :rtype: markupsafe.Markup
        """
        # profiling code
        current_thread = threading.current_thread()
        execution_context_enabled = getattr(current_thread, "profiler_params", {}).get(
            "execution_context_qweb"
        )
        qweb_hooks = getattr(current_thread, "qweb_hooks", ())
        if execution_context_enabled or qweb_hooks:
            # To have the new compilation cached because the generated code will change.
            # Therefore 'profile' is a key to the cache.
            options["profile"] = True

        values = values.copy() if values else {}
        # The t-call content slot is keyed by the *integer* 0 at render time:
        # ``T_CALL_SLOT`` ("0") interpolated bare into the generated f-strings
        # becomes an int literal (``values.get(0, '')``). A caller must not
        # pre-occupy the slot, so strip both spellings — guarding only the str
        # form (the historical behaviour) silently let an int-0 value leak into
        # the slot.
        if T_CALL_SLOT in values or 0 in values:
            _logger.warning(
                "values[0] should be unset when call the _render method and only set into the template."
            )
            values.pop(T_CALL_SLOT, None)
            values.pop(0, None)

        irQweb = self.with_context(**options)._prepare_environment(values)
        irQweb = irQweb.with_context(
            # List of generated and/or used functions, used for optimal performance
            __qweb_loaded_functions={},
            # List of codes generated during compilation. It is mainly used for debugging and displaying error messages.
            __qweb_loaded_codes={},
            __qweb_loaded_options={},
            # Reference to the last node being compiled. It is mainly used for debugging and displaying error messages.
            _qweb_error_path_xml=[None, None, None],
        )

        safe_eval.check_values(values)

        root_values = values.copy()
        values["__qweb_root_values"] = root_values["__qweb_root_values"] = root_values

        iterator = irQweb._render_iterall(template, None, values)
        return Markup("".join(iterator))

    def _render_iterall(
        self,
        view_ref: int | str | etree._Element,
        method: str | None,
        values: dict[str, Any],
        directive: str = "render",
    ) -> Iterator[str]:
        """Iterate over the generator method.
        Generator elements are a str
        """
        root_values = values["__qweb_root_values"]
        loaded_functions = self.env.context["__qweb_loaded_functions"]

        params = QwebCallParameters(
            context={},
            view_ref=view_ref,
            method=method,
            values=None,
            scope=False,
            directive=directive,
            path_xml=None,
        )
        stack = [QwebStackFrame(params, self, iter([params]), values, None)]

        try:
            while stack:
                if len(stack) > QWEB_MAX_RENDER_DEPTH:
                    msg = "Qweb template infinite recursion"
                    raise RecursionError(msg)

                frame = stack[-1]

                # traverse the iterator
                for item in frame.iterator:
                    # To debug the rendering step by step you can log the (len(stack) * '  ', repr(item))
                    if isinstance(item, str):
                        yield item
                        continue

                    # use QwebContent params or return already evaluated QwebContent
                    if is_content := isinstance(item, QwebContent):
                        if item.html is not None:
                            yield item.html
                            continue
                        params = item.params__

                    else:  # isinstance(item, QwebCallParameters)
                        params = item

                    # add new QwebStackFrame from QwebCallParameters
                    values = frame.values
                    irQweb = frame.irQweb

                    # Use the current directive context
                    if params.context:
                        irQweb = irQweb.with_context(**params.context)

                    render_template = loaded_functions.get(params.method)

                    # Fetch the compiled function and template options
                    if not render_template:
                        template_functions, def_name, options = irQweb._compile(
                            params.view_ref
                        )
                        loaded_functions.update(template_functions)
                        render_template = template_functions[params.method or def_name]
                    else:
                        options = irQweb._compile(params.view_ref)[2]

                    # Apply a new scope if needed
                    if params.scope:
                        if params.scope == "root":
                            values = root_values
                        values = values.copy()

                    # Update values with default values
                    if params.values:
                        values.update(params.values)

                    iterator = iter([])
                    try:
                        # Create the iterator from the template
                        iterator = render_template(irQweb, values)
                    finally:
                        if is_content and self.env.context["_qweb_error_path_xml"][1]:
                            # add a stack frame to log a complete error with the path when compile the template
                            logParams = QwebCallParameters(
                                *(
                                    params[0:-1]
                                    + (tuple(self.env.context["_qweb_error_path_xml"]),)
                                )
                            )
                            stack.append(
                                QwebStackFrame(logParams, irQweb, [], values, options)
                            )
                        stack.append(
                            QwebStackFrame(params, irQweb, iterator, values, options)
                        )
                    break

                else:
                    stack.pop()

        except (
            TransactionRollback,
            SerializationFailure,
            DeadlockDetected,
            ReadOnlySqlTransaction,
        ):
            raise

        except Exception as error:
            qweb_error_info = self._get_error_info(error, stack, stack[-1])
            if qweb_error_info.template is None and qweb_error_info.ref is None:
                qweb_error_info.ref = view_ref

            if hasattr(error, "qweb"):
                if qweb_error_info.source:
                    error.qweb.source = qweb_error_info.source + error.qweb.source
                if not error.qweb.ref and frame.params.view_ref:
                    error.qweb.ref = frame.params.view_ref
                qweb_error_info = error.qweb
            elif not isinstance(error, UserError):
                # If is not an odoo Exception check if the current error is raise from
                # IrQweb (models or computed code). In this case, convert it into an QWebError.
                isQweb = False

                trace = error.__traceback__
                tb_frames = [trace.tb_frame]
                while trace.tb_next is not None:
                    trace = trace.tb_next
                    tb_frames.append(trace.tb_frame)
                for tb_frame in tb_frames[::-1]:
                    if tb_frame.f_globals.get("__name__") == __name__ or (
                        isinstance(tb_frame.f_locals.get("self"), models.AbstractModel)
                        and tb_frame.f_locals["self"]._name == self._name
                    ):
                        isQweb = True
                        break
                    if any(
                        path in tb_frame.f_code.co_filename
                        for path in tools.config["addons_path"]
                    ):
                        break

                if isQweb:
                    raise QWebError(qweb_error_info) from error

            error.qweb = qweb_error_info
            raise

    def _get_error_info(
        self,
        error: Exception,
        stack: list[QwebStackFrame],
        frame: QwebStackFrame,
    ) -> QWebErrorInfo:
        no_id_ref = "etree._Element"

        path = None
        html = None
        loaded_codes = self.env.context["__qweb_loaded_codes"]
        if (
            frame.params.view_ref in loaded_codes
            and not isinstance(error, RecursionError)
        ) or len(stack) <= 1:
            options = (
                frame.options or {}
            )  # The compilation may have failed before the compilation options were loaded.
            if "ref" not in options:
                options = (
                    self.env.context["__qweb_loaded_options"].get(frame.params.view_ref)
                    or {}
                )
            ref = (
                options.get("ref") or frame.params.view_ref
            )  # The template can have a null reference, for example for a provided etree.
            ref_name = options.get("ref_name") or None
            code = loaded_codes.get(frame.params.view_ref) or loaded_codes.get(
                no_id_ref
            )
            if ref == self.env.context["_qweb_error_path_xml"][0]:
                path = self.env.context["_qweb_error_path_xml"][1]
                html = self.env.context["_qweb_error_path_xml"][2]
        else:
            # get the previous caller (like t-call) to display erroneous xml node.
            options = (
                stack[-2].options or {}
            )  # The compilation may have failed before the compilation options were loaded.
            ref = options.get("ref")
            ref_name = options.get("ref_name")
            code = loaded_codes.get(ref) or loaded_codes.get(no_id_ref)
            if frame.params.path_xml:
                path = frame.params.path_xml[1]
                html = frame.params.path_xml[2]

        source_file_ref = None if ref == no_id_ref else ref
        line_nb = 0
        trace = traceback.format_exc()
        for error_line in reversed(trace.split("\n")):
            if f'File "<{source_file_ref}>"' in error_line or (
                ref is None and 'File "<' in error_line
            ):
                line_function = error_line.split(", line ")[1]
                line_nb = int(line_function.split(",")[0])
                break

        source = [info.params.path_xml for info in stack if info.params.path_xml]
        code_lines = (code or "").split("\n")

        found = False
        for code_line in reversed(code_lines[:line_nb]):
            if code_line.startswith("def "):
                break
            match = re.match(r"\s*# element: (.*) , (.*)", code_line)
            if not match:
                if found:
                    break
                continue
            if found:
                info = (ref, match[1][1:-1], match[2][1:-1])
                if info not in source:
                    source.append(info)
            else:
                found = True
                path = match[1][1:-1]
                html = match[2][1:-1]

        if path:
            source.append((ref, path, html))

        surrounding = None
        if self.env.context.get("dev_mode") and line_nb:
            if (
                html
                and " t-if=" in html
                and " if " in "\n".join(code_lines[line_nb - 2 : line_nb - 1])
            ):
                line_nb -= 1
            previous_lines = "\n".join(code_lines[max(line_nb - 25, 0) : line_nb - 1])
            line = code_lines[line_nb - 1]
            next_lines = "\n".join(code_lines[line_nb : line_nb + 5])
            indent = re.search(r"^(\s*)", line).group(0)
            surrounding = textwrap.indent(
                textwrap.dedent(
                    f"{previous_lines}\n"
                    f"{indent}########### Line triggering the error ############\n{line}\n"
                    f"{indent}##################################################\n{next_lines}"
                ),
                " " * 8,
            )

        return QWebErrorInfo(
            f"{error.__class__.__name__}: {error}",
            ref if ref_name is None else ref_name,
            ref,
            path,
            html,
            source,
            surrounding,
        )

    # assume cache will be invalidated by third party on write to ir.ui.view
    def _get_template_cache_keys(self) -> list[str]:
        """Return the list of context keys to use for caching ``_compile``."""
        return [
            "lang",
            "inherit_branding",
            "inherit_branding_auto",
            "edit_translations",
            "profile",
        ]

    def _get_template_info(self, template: int | str) -> dict[str, Any]:
        return self.env["ir.ui.view"]._get_cached_template_info(template)

    def _compile(
        self, template: int | str | etree._Element
    ) -> tuple[dict[str, Any], str, frozendict]:
        ref = None
        if isinstance(template, str) and template.endswith(".xml"):
            module_path = Manifest.for_addon(Path(template).parts[0]).path
            if (
                "templates"
                not in Path(file_path(template)).relative_to(module_path).parts
            ):
                msg = "The templates file %s must be under a subfolder 'templates' of a module"
                raise ValueError(
                    msg,
                    template,
                )
            with file_open(template, "rb", filter_ext=(".xml",)) as file:
                raw = file.read()
                template = etree.fromstring(memoryview(raw))
        elif not isinstance(template, etree._Element):
            ref = self._get_template_info(template)["id"]

        if ref:
            template_functions, def_name, options = self._generate_code_cached(ref)
        else:
            template_functions, def_name, options = self._generate_code_uncached(
                template
            )

        render_template = template_functions[def_name]
        if (
            options.get("profile")
            and render_template.__name__ != "profiled_method_compile"
        ):
            ref = options.get("ref")
            ref_xml = str(val) if (val := options.get("ref_xml")) else None

            def wrap(function: FunctionType) -> FunctionType:
                def profiled_method_compile(self: Any, values: dict[str, Any]) -> Any:
                    qweb_tracker = QwebTracker(ref, ref_xml, self.env.cr)
                    self = self.with_context(qweb_tracker=qweb_tracker)
                    if qweb_tracker.execution_context_enabled:
                        with ExecutionContext(template=ref):
                            return function(self, values)
                    return function(self, values)

                return profiled_method_compile

            for key, function in template_functions.items():
                if isinstance(function, FunctionType):
                    template_functions[key] = wrap(function)

        return (template_functions, def_name, options)

    @tools.conditional(
        "xml" not in tools.config["dev_mode"],
        tools.ormcache(
            "ref",
            "tuple(self.env.context.get(k) or False for k in self._get_template_cache_keys())",
            cache="templates",
        ),
    )
    def _generate_code_cached(self, ref: int) -> tuple[dict[str, Any], str, frozendict]:
        return self._generate_code_uncached(ref)

    def _generate_code_uncached(
        self, template: int | str | etree._Element
    ) -> tuple[dict[str, Any], str, frozendict]:
        ref = (
            self._get_template_info(template)["id"]
            if isinstance(template, (int, str))
            else None
        )

        code, options, def_name = self._generate_code(template)

        if code is None:
            Error, message, stack = options["error"]

            def not_found_template(self: Any, values: dict[str, Any]) -> str:
                if tools.config["dev_mode"]:
                    _logger.info(stack)
                if self.env.context.get("raise_if_not_found", True):
                    raise Error(message)
                _logger.warning("Cannot load template %s: %s", template, message)
                return ""

            return (
                {"not_found_template": not_found_template},
                "not_found_template",
                frozendict(options),
            )

        wrap_code = "\n".join(
            [
                "def generate_functions():",
                indent_code(code, 1),
                f"    code = {code!r}",
                "    return template_functions",
            ]
        )
        compiled = compile(wrap_code, f"<{ref}>", "exec")
        globals_dict = self.__prepare_globals()
        globals_dict["__builtins__"] = (
            globals_dict  # So that unknown/unsafe builtins are never added.
        )
        unsafe_eval(compiled, globals_dict)
        return (
            globals_dict["generate_functions"](),
            def_name,
            frozendict(options),
        )

    def _generate_code(
        self, template: int | str | etree._Element
    ) -> tuple[str | None, dict[str, Any], str]:
        """Compile the given template into a rendering function (generator)::

            render_template(qweb, values)

        This method can be called only by :meth:`_render` method or by
        the compiled code of t-call from an other template.

        An ``options`` dictionary is created and attached to the function.
        It contains rendering options that are part of the cache key in
        addition to template references.

        where ``qweb`` is a QWeb instance and ``values`` are the values to
        render.

        :returns: tuple containing code, options and main method name
        """
        if not isinstance(template, (int, str, etree._Element)):
            template = str(template)
        # The `compile_context`` dictionary includes the elements used for the
        # cache key to which are added the template references as well as
        # technical information useful for generating the function. This
        # dictionary is only used when compiling the template.
        compile_context = self.env.context.copy()

        try:
            element, document, ref = self._get_template(template)
        except (ValueError, UserError) as e:
            # return the error information if the template is not found or fail
            options = {
                k: compile_context.get(k, False)
                for k in self._get_template_cache_keys()
            }
            message = str(e)
            if hasattr(e, "context") and e.context.get("view"):
                message = f"{message} (view: {e.context['view'].key})"
            options["error"] = (e.__class__, message, traceback.format_exc())
            return (None, options, "not_found_template")

        compile_context.pop("raise_if_not_found", None)

        ref_name = element.attrib.pop("t-name", None)
        if isinstance(ref, int) or (isinstance(template, str) and "<" not in template):
            ref_name = self._get_template_info(ref)["key"] or ref_name

        # reference to get xml and etree (usually the template ID)
        compile_context["ref"] = ref
        # reference name or key to get xml and etree (usually the template XML ID)
        compile_context["ref_name"] = ref_name
        # str xml of the reference template used for compilation. Useful for debugging, dev mode and profiling.
        compile_context["ref_xml"] = str(document) if document else None
        # Identifier used to call `_compile`
        compile_context["template"] = template
        # Root of the etree which will be processed during compilation.
        compile_context["root"] = element.getroottree()
        # Reference to the last node being compiled. It is mainly used for debugging and displaying error messages.
        compile_context["_qweb_error_path_xml"] = compile_context.get(
            "_qweb_error_path_xml", [None, None, None]
        )

        compile_context["nsmap"] = {
            ns_prefix: str(ns_definition)
            for ns_prefix, ns_definition in compile_context.get("nsmap", {}).items()
        }

        # The options dictionary includes cache key elements and template
        # references. It will be attached to the generated function. This
        # dictionary is only there for logs, performance or test information.
        # The values of these `options` cannot be changed and must always be
        # identical in `context` and `self.env.context`.
        options = {
            key: compile_context.get(key, False)
            for key in self._get_template_cache_keys() + ["ref", "ref_name"]
        }

        # generate code
        ref_name = compile_context["ref_name"] or ""
        if isinstance(template, etree._Element):
            def_name = TO_VARNAME_REGEXP.sub(
                r"_", f"template_etree_{next(ETREE_TEMPLATE_REF)}"
            )
        else:
            def_name = TO_VARNAME_REGEXP.sub(
                r"_",
                f"template_{ref_name if '<' not in ref_name else ''}_{ref}",
            )

        name_gen = count()
        compile_context["make_name"] = lambda prefix: (
            f"{def_name}_{prefix}_{next(name_gen)}"
        )

        if element.text:
            element.text = FIRST_RSTRIP_REGEXP.sub(r"\2", element.text)

        compile_context["template_functions"] = {}

        compile_context["_text_concat"] = []
        self._append_text(
            "", compile_context
        )  # To ensure the template function is a generator and doesn't become a regular function
        compile_context["template_functions"][f"{def_name}_content"] = (
            [f"def {def_name}_content(self, values):"]
            + self._compile_node(element, compile_context, 2)
            + self._flush_text(compile_context, 2, rstrip=True)
        )

        compile_context["template_functions"][def_name] = [
            indent_code(
                f"""
            def {def_name}(self, values):
                if 'xmlid' not in values:
                    values['xmlid'] = {options["ref_name"]!r}
                    values['viewid'] = {options["ref"]!r}
                self.env.context['__qweb_loaded_functions'].update(template_functions)
                self.env.context['__qweb_loaded_options'][{options["ref"]!r}] = self.env.context['__qweb_loaded_options'][{options["ref_name"]!r}] = template_options
                self.env.context['__qweb_loaded_codes'][{options["ref"]!r}] = self.env.context['__qweb_loaded_codes'][{options["ref_name"]!r}] = code
                yield from {def_name}_content(self, values)
                """,
                0,
            )
        ]

        code_lines = []
        code_lines.extend(
            (
                f"template_options = {pprint.pformat(options, indent=4)}",
                "code = None",
                "template_functions = {}",
            )
        )

        for lines in compile_context["template_functions"].values():
            code_lines.extend(lines)

        code_lines.extend(
            f"template_functions[{name!r}] = {name}"
            for name in compile_context["template_functions"]
        )

        code = "\n".join(code_lines)

        if options.get("profile"):
            options["ref_xml"] = compile_context["ref_xml"]

        return (code, options, def_name)

    # read and load input template

    def _get_template(
        self, template: int | str | etree._Element
    ) -> tuple[etree._Element, str, str | int]:
        """Retrieve the given template, and return it as a tuple ``(etree,
        xml, ref)``, where ``element`` is an etree, ``document`` is the
        string document that contains ``element``, and ``ref`` is the unique
        reference of the template (id, t-name or template).

        :param template: template identifier or etree
        """
        if template in (False, None, ""):
            raise ValueError("template is required")

        # template is an xml etree already
        if isinstance(template, etree._Element):
            document = etree.tostring(template, encoding="unicode")
            # Compilation is destructive — each directive pops the attributes it
            # consumes (see _compile_node / _compile_directives) — so never
            # compile the caller's own element. A reused etree (rendered more
            # than once, or kept by the caller) would otherwise be stripped
            # after the first render and silently produce corrupted output.
            element = deepcopy(template)

            # <templates>
            #   <template t-name=... /> <!-- return ONLY this element -->
            #   <template t-name=... />
            # </templates>
            for node in element.iter():
                ref = node.get("t-name")
                if ref:
                    return (node, document, _id_or_xmlid(ref))

            return (element, document, "etree._Element")

        # template is xml as string
        if isinstance(template, str) and "<" in template:
            msg = "Inline templates must be passed as `etree` documents"
            raise ValueError(msg)

        # template is (id or ref) to a database stored template
        id_or_xmlid = _id_or_xmlid(
            template
        )  # e.g. <t t-call="33"/> or <t t-call="web.layout"/>
        value = self._preload_trees([id_or_xmlid]).get(id_or_xmlid)
        if value.get("error"):
            raise value["error"]

        # ``value["tree"]`` is cached for the whole transaction in
        # ``cr.cache["_compile_batch_"]`` (see ``_preload_trees``). Compilation
        # is destructive (each directive pops the attributes it consumes), so it
        # MUST run on a private copy: otherwise a recompile — triggered by a
        # mid-transaction eviction of the bounded ``templates`` ormcache — reads
        # an already-stripped tree and silently renders corrupted output. The
        # copy was previously made only in xml-dev mode (where
        # ``_generate_code_cached`` is uncached and the tree is processed
        # repeatedly); cache eviction gives production the same exposure.
        value_tree = deepcopy(value["tree"])
        # return etree, document and ref
        return (value_tree, value["template"], value["ref"])

    @api.model
    def _get_preload_attribute_xmlids(self) -> list[str]:
        return ["t-call"]

    def _preload_trees(
        self, refs: Sequence[int | str]
    ) -> dict[int | str, dict[str, Any]]:
        """Preload all tree and subtree (from t-call and other '_get_preload_attribute_xmlids' values).

        Returns::

            {
                id or xmlId / key: {
                    "xmlid": str | None,
                    "ref": int | None,
                    "tree": etree | None,
                    "template": str | None,
                    "error": None | MissingError,
                }
            }
        """
        compile_batch = self.env["ir.ui.view"]._preload_views(refs)

        refs = list(map(_id_or_xmlid, refs))
        missing_refs = {
            ref: compile_batch[ref]
            for ref in refs
            if "template" not in compile_batch[ref] and not compile_batch[ref]["error"]
        }
        if not missing_refs:
            return compile_batch

        xmlids = list(missing_refs)
        missing_refs_values = list(missing_refs.values())
        views = (
            self.env["ir.ui.view"]
            .sudo()
            .union(*[data["view"] for data in missing_refs_values])
        )

        trees = views._get_view_etrees()

        # add in cache
        for xmlid, view, tree in zip(xmlids, views, trees, strict=True):
            data = {
                "tree": tree,
                "template": etree.tostring(tree, encoding="unicode"),
            }
            compile_batch[view.id].update(data)
            compile_batch[xmlid].update(data)

        # preload sub template
        ref_names = self._get_preload_attribute_xmlids()
        sub_refs = OrderedSet()
        for tree in trees:
            sub_refs.update(
                el.get(ref_name)
                for ref_name in ref_names
                for el in tree.xpath(f"//*[@{ref_name}]")
                if not any(
                    att.startswith("t-options-") or att in {"t-options", "t-lang"}
                    for att in el.attrib
                )
                if "{" not in el.get(ref_name)
                and "<" not in el.get(ref_name)
                and "/" not in el.get(ref_name)
            )
        if any(not f for f in sub_refs):
            raise ValueError("template is required")
        self._preload_trees(list(sub_refs))

        # not found template
        for ref in missing_refs:
            if ref not in compile_batch:
                compile_batch[ref] = {
                    "xmlid": ref,
                    "ref": ref,
                    "error": MissingError(
                        self.env._("External ID can not be loaded: %s", ref)
                    ),
                }

        return compile_batch

    # values for running time

    def _get_converted_image_data_uri(self, base64_source: str | bytes) -> str:
        if self.env.context.get("webp_as_jpg"):
            mimetype = FILETYPE_BASE64_MAGICWORD.get(base64_source[:1], "png")
            if "webp" in mimetype:
                # Convert WebP to JPEG for PDF rendering (WeasyPrint).
                bin_source = base64.b64decode(base64_source)
                Attachment = self.env["ir.attachment"]
                checksum = Attachment._content_checksum(bin_source)
                origins = Attachment.sudo().search(
                    [
                        [
                            "id",
                            "!=",
                            False,
                        ],  # No implicit condition on res_field.
                        ["checksum", "=", checksum],
                    ]
                )
                if origins:
                    converted_domain = [
                        [
                            "id",
                            "!=",
                            False,
                        ],  # No implicit condition on res_field.
                        ["res_model", "=", "ir.attachment"],
                        ["res_id", "in", origins.ids],
                        ["mimetype", "=", "image/jpeg"],
                    ]
                    converted = Attachment.sudo().search(converted_domain, limit=1)
                    if converted:
                        base64_source = converted.datas
        return image_data_uri(base64_source)

    def _prepare_environment(self, values: dict[str, Any]) -> Self:
        """Prepare the values and context sent to the compiled and evaluated
        function.

        :param values: template values to be used for rendering
        :return: self (with new context)
        """
        debug = (request and request.session.debug) or ""
        values.update(
            true=True,
            false=False,
        )
        if not self.env.context.get("minimal_qcontext"):
            values.setdefault("debug", debug)
            values.setdefault("user_id", self.env.user.with_env(self.env))
            values.setdefault("res_company", self.env.company.sudo())
            values.update(
                request=request,  # might be unbound if we're not in an httprequest context
                test_mode_enabled=config["test_enable"],
                json=qwebJSON,
                quote_plus=urllib.parse.quote_plus,
                time=safe_eval.time,
                datetime=safe_eval.datetime,
                relativedelta=relativedelta,
                image_data_uri=self._get_converted_image_data_uri,
                # specific 'math' functions to ease rounding in templates and lessen controller marshmalling
                floor=math.floor,
                ceil=math.ceil,
                env=self.env,
                lang=self.env.context.get("lang"),
                keep_query=keep_query,
            )

        context = {"dev_mode": "qweb" in tools.config["dev_mode"]}
        return self.with_context(**context)

    def __prepare_globals(self) -> dict[str, Any]:
        """Prepare the global context sent to eval the qweb generated code."""
        return {
            "__name__": __name__,
            "Sized": Sized,
            "Mapping": Mapping,
            "Markup": Markup,
            "escape": escape,
            "VOID_ELEMENTS": VOID_ELEMENTS,
            "QwebCallParameters": QwebCallParameters,
            "QwebContent": QwebContent,
            "ValueError": ValueError,
            **_BUILTINS,
        }

    # helpers for compilation

    def _append_text(
        self, text: str | bytes | None, compile_context: dict[str, Any]
    ) -> None:
        """Add an item (converts to a string) to the list.
        This will be concatenated and added during a call to the
        `_flush_text` method. This makes it possible to return only one
        yield containing all the parts."""
        compile_context["_text_concat"].append(self._compile_to_str(text))

    def _rstrip_text(self, compile_context: dict[str, Any]) -> str:
        """The text to flush is right stripped, and the stripped content are
        returned.
        """
        text_concat = compile_context["_text_concat"]
        if not text_concat:
            return ""

        result = RSTRIP_REGEXP.search(text_concat[-1])
        strip = result.group(0) if result else ""
        text_concat[-1] = RSTRIP_REGEXP.sub("", text_concat[-1])

        return strip

    def _flush_text(
        self, compile_context: dict[str, Any], level: int, rstrip: bool = False
    ) -> list[str]:
        """Concatenate all the textual chunks added by ``_append_text`` into a
        single ``yield`` line. Return an empty list if there is no text to flush.

        :param bool rstrip: if set, right-strip the concatenated text.
        :rtype: list[str]
        """
        text_concat = compile_context["_text_concat"]
        if not text_concat:
            return []
        if rstrip:
            self._rstrip_text(compile_context)
        text = "".join(text_concat)
        text_concat.clear()
        return [f"{'    ' * level}yield {text!r}"]

    def _is_static_node(
        self, el: etree._Element, compile_context: dict[str, Any]
    ) -> bool:
        """Test whether the given element is purely static, i.e. (there
        are no t-* attributes), does not require dynamic rendering for its
        attributes.
        """
        return (
            el.tag != "t"
            and "groups" not in el.attrib
            and not any(
                att.startswith("t-") and att not in ("t-tag-open", "t-inner-content")
                for att in el.attrib
            )
        )

    # compile python expression and format string

    def _compile_format(self, expr: str) -> str:
        """Parses the provided format string and compiles it to a single
        expression python, uses string with format method.
        Use format is faster to concat string and values.
        """
        # <t t-setf-name="Hello #{world} %s !"/>
        # =>
        # values['name'] = 'Hello %s %%s !' % (values['world'],)
        values = [
            f"self._compile_to_str({self._compile_expr(m.group(1) or m.group(2))})"
            for m in FORMAT_REGEX.finditer(expr)
        ]
        code = repr(FORMAT_REGEX.sub("%s", expr.replace("%", "%%")))
        if values:
            code += f" % ({', '.join(values)},)"
        return code

    def _compile_expr_tokens(
        self,
        tokens: list[tokenize.TokenInfo],
        allowed_keys: list[str] | frozenset[str],
        argument_names: list[str] | None = None,
        raise_on_missing: bool = False,
    ) -> str:
        """Transform the list of tokens into a python instruction in textual
        form by namespacing the dynamic values.

        Example: `5 + a + b.c` to be `5 + values.get('a') + values['b'].c`
        Unknown values are considered to be None, but using `values['b']`
        gives a clear error message in cases where there is an attribute for
        example (have a `KeyError: 'b'`, instead of `AttributeError: 'NoneType'
        object has no attribute 'c'`).

        :rtype: str
        """
        # Finds and extracts the current "scope"'s "allowed values": values
        # which should not be accessed through the environment's namespace:
        # * the local variables of a lambda should be accessed directly e.g.
        #     lambda a: a + b should be compiled to lambda a: a + values['b'],
        #     since a is local to the lambda it has to be accessed directly
        #     but b needs to be accessed through the rendering environment
        # * similarly for a comprehensions [a + b for a in c] should be
        #     compiledto [a + values.get('b') for a in values.get('c')]
        # to avoid the risk of confusion between nested lambdas / comprehensions,
        # this is currently performed independently at each level of brackets
        # nesting (hence the function being recursive).
        open_bracket_index = -1
        bracket_depth = 0

        argument_name = "_arg_%s__"
        argument_names = argument_names or []

        for index, t in enumerate(tokens):
            if t.exact_type in [token.LPAR, token.LSQB, token.LBRACE]:
                bracket_depth += 1
            elif t.exact_type in [token.RPAR, token.RSQB, token.RBRACE]:
                bracket_depth -= 1
            elif bracket_depth == 0 and t.exact_type == token.NAME:
                string = t.string
                if (
                    string == "lambda"
                ):  # lambda => allowed values for the current bracket depth
                    for i in range(index + 1, len(tokens)):
                        t = tokens[i]
                        if t.exact_type == token.NAME:
                            argument_names.append(t.string)
                        elif t.exact_type == token.COMMA:
                            pass
                        elif t.exact_type == token.COLON:
                            break
                        elif t.exact_type == token.EQUAL:
                            msg = "Lambda default values are not supported"
                            raise NotImplementedError(msg)
                        else:
                            msg = "This lambda code style is not implemented."
                            raise NotImplementedError(msg)
                elif (
                    string == "for"
                ):  # list comprehensions => allowed values for the current bracket depth
                    for i in range(index + 1, len(tokens)):
                        t = tokens[i]
                        if t.exact_type == token.NAME:
                            if t.string == "in":
                                break
                            argument_names.append(t.string)
                        elif t.exact_type in [
                            token.COMMA,
                            token.LPAR,
                            token.RPAR,
                        ]:
                            pass
                        else:
                            msg = "This loop code style is not implemented."
                            raise NotImplementedError(msg)

        # Use bracket to nest structures.
        # Recursively processes the "sub-scopes", and replace their content with
        # a compiled node. During this recursive call we add to the allowed
        # values the values provided by the list comprehension, lambda, etc.,
        # previously extracted.
        index = 0
        open_bracket_index = -1
        bracket_depth = 0

        while index < len(tokens):
            t = tokens[index]
            string = t.string

            if t.exact_type in [token.LPAR, token.LSQB, token.LBRACE]:
                if bracket_depth == 0:
                    open_bracket_index = index
                bracket_depth += 1
            elif t.exact_type in [token.RPAR, token.RSQB, token.RBRACE]:
                bracket_depth -= 1
                if bracket_depth == 0:
                    code = self._compile_expr_tokens(
                        tokens[open_bracket_index + 1 : index],
                        list(allowed_keys),
                        list(argument_names),
                        raise_on_missing,
                    )
                    code = tokens[open_bracket_index].string + code + t.string
                    tokens[open_bracket_index : index + 1] = [
                        tokenize.TokenInfo(
                            token.QWEB,
                            code,
                            tokens[open_bracket_index].start,
                            t.end,
                            "",
                        )
                    ]
                    index = open_bracket_index

            index += 1

        # The keys will be namespaced by values if they are not allowed. In
        # order to have a clear keyError message, this will be replaced by
        # values['key'] for certain cases (for example if an attribute is called
        # key.attrib, or an index key[0] ...)
        code = []
        index = 0
        pos = tokens and tokens[0].start  # to keep level when use expr on multi line
        while index < len(tokens):
            t = tokens[index]
            string = t.string

            if t.start[0] != pos[0]:
                pos = (t.start[0], 0)
            space = t.start[1] - pos[1]
            if space:
                code.append(" " * space)
            pos = t.start

            if t.exact_type == token.NAME:
                if "__" in string:
                    raise SyntaxError(
                        f"Using variable names with '__' is not allowed: {string!r}"
                    )
                if string == "lambda":  # lambda => allowed values
                    code.append("lambda ")
                    index += 1
                    while index < len(tokens):
                        t = tokens[index]
                        if t.exact_type == token.NAME and t.string in argument_names:
                            code.append(argument_name % t.string)
                        if t.exact_type in [token.COMMA, token.COLON]:
                            code.append(t.string)
                        if t.exact_type == token.COLON:
                            break
                        index += 1
                    if t.end[0] != pos[0]:
                        pos = (t.end[0], 0)
                    else:
                        pos = t.end
                elif string in argument_names:
                    code.append(argument_name % t.string)
                elif (
                    string in allowed_keys
                    or (
                        index + 1 < len(tokens)
                        and tokens[index + 1].exact_type == token.EQUAL
                    )
                    or (
                        index > 0
                        and tokens[index - 1]
                        and tokens[index - 1].exact_type == token.DOT
                    )
                ):
                    code.append(string)
                elif raise_on_missing or (
                    index + 1 < len(tokens)
                    and tokens[index + 1].exact_type
                    in [token.DOT, token.LPAR, token.LSQB, token.QWEB]
                ):
                    # Should have values['product'].price to raise an error when get
                    # the 'product' value and not an 'NoneType' object has no
                    # attribute 'price' error.
                    code.append(f"values[{string!r}]")
                else:
                    # not assignation allowed, only getter
                    code.append(f"values.get({string!r})")
            elif t.type not in [
                tokenize.ENCODING,
                token.ENDMARKER,
                token.DEDENT,
            ]:
                code.append(string)

            if t.end[0] != pos[0]:
                pos = (t.end[0], 0)
            else:
                pos = t.end

            index += 1

        return "".join(code)

    # Cache for _compile_expr: (expr, raise_on_missing) → compiled expression string.
    # Result is deterministic — _compile_expr_tokens uses no instance state. An LRU
    # (rather than a plain dict cleared wholesale at the cap) avoids a periodic
    # full-recompile stampede once the set of distinct expressions exceeds the cap.
    # _compile_expr runs only at template-compile time (its output is cached one
    # layer up by @ormcache on _generate_code_cached), so LRU.get's per-hit cost is
    # off the warm render path. Benchmarked: ~3.7x fewer redundant recompiles under
    # churn past the cap (QWEB-P1).
    _compile_expr_cache = LRU(8192)

    def _compile_expr(self, expr: str, raise_on_missing: bool = False) -> str:
        """Transform a string into a python instruction in textual form by
        namespacing the dynamic values.
        Tokenizes the string and calls ``_compile_expr_tokens``.

        :param str expr: python expression
        :param bool raise_on_missing:
            Compile has `values['product'].price` instead of
            `values.get('product').price` to raise an error when get the
            'product' value and not an 'NoneType' object has no attribute
            'price' error.
        """
        cache_key = (expr, raise_on_missing)
        result = self._compile_expr_cache.get(cache_key)
        if result is not None:
            return result

        # Parentheses are useful for compiling multi-line expressions such as
        # conditions existing in some templates. (see test_compile_expr tests)
        readable = io.BytesIO(f"({expr or ''})".encode())
        try:
            tokens = list(tokenize.tokenize(readable.readline))
        except tokenize.TokenError:
            raise ValueError(f"Can not compile expression: {expr}") from None

        expression = self._compile_expr_tokens(
            tokens, ALLOWED_KEYWORD, raise_on_missing=raise_on_missing
        )

        assert_valid_codeobj(
            _SAFE_QWEB_OPCODES, compile(expression, "<>", "eval"), expr
        )

        result = f"({expression})"
        self._compile_expr_cache[cache_key] = result
        return result

    def _compile_bool(self, attr: str | bool | None, default: bool = False) -> bool:
        """Convert the statements as a boolean."""
        if attr:
            if attr is True:
                return True
            attr = attr.lower()
            if attr in ("false", "0"):
                return False
            elif attr in ("true", "1"):
                return True
        return bool(default)

    def _compile_to_str(self, expr: Any) -> str:
        """Generate a string from an arbitrary source."""
        if expr is None or expr is False:
            return ""

        if isinstance(expr, str):
            return expr
        elif isinstance(expr, bytes):
            return expr.decode()
        else:
            return str(expr)

    # order

    def _directives_eval_order(self) -> list[str]:
        """List all supported directives in the order in which they should be
        evaluated on a given element. For instance, a node bearing both
        ``foreach`` and ``if`` should see ``foreach`` executed before ``if``
        aka

        .. code-block:: xml

            <el t-foreach="foo" t-as="bar" t-if="bar">

        should be equivalent to

        .. code-block:: xml

            <t t-foreach="foo" t-as="bar">
                <t t-if="bar">
                    <el>

        then this method should return ``['foreach', 'if']``.
        """
        return [
            "elif",  # Must be the first because compiled by the previous if.
            "else",  # Must be the first because compiled by the previous if.
            "debug",
            "groups",
            "as",
            "foreach",
            "if",
            "call-assets",
            "lang",
            "options",
            "call",
            "att",
            "field",
            "esc",
            "raw",
            "out",
            "tag-open",
            "set",
            "inner-content",
            "tag-close",
        ]

    # compile

    def _compile_node(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the given element into python code.

        The t-* attributes (directives) are converted to python instructions. If
        there are no t-* attributes, the element is considered static.

        Directives are compiled in the order given by ``_directives_eval_order``
        (which creates the ``compile_context['iter_directives']`` iterator). Only
        directives with a ``_compile_directive_*`` method are supported.

        :return: list of string
        """
        # Internal directive used to skip a rendering.
        if "t-qweb-skip" in el.attrib:
            return []

        # if tag don't have qweb attributes don't use directives
        if self._is_static_node(el, compile_context):
            return self._compile_static_node(el, compile_context, level)

        path = compile_context["root"].getpath(el)
        xml = etree.tostring(etree.Element(el.tag, el.attrib), encoding="unicode")
        compile_context["_qweb_error_path_xml"][0] = compile_context["ref"]
        compile_context["_qweb_error_path_xml"][1] = path
        compile_context["_qweb_error_path_xml"][2] = xml
        body = [indent_code(f"# element: {path!r} , {xml!r}", level)]

        # create an iterator on directives to compile in order
        compile_context["iter_directives"] = iter(self._directives_eval_order())

        # add technical directive tag-open, tag-close, inner-content and take
        # care of the namspace
        if not el.nsmap:
            unqualified_el_tag = el_tag = el.tag
        else:
            # Etree will remove the ns prefixes indirection by inlining the corresponding
            # nsmap definition into the tag attribute. Restore the tag and prefix here.
            # Note: we do not support namespace dynamic attributes, we need a default URI
            # on the root and use attribute directive t-att="{'xmlns:example': value}".
            unqualified_el_tag = etree.QName(el.tag).localname
            el_tag = unqualified_el_tag
            if el.prefix:
                el_tag = f"{el.prefix}:{el_tag}"

        if unqualified_el_tag != "t":
            el.set("t-tag-open", el_tag)
            if el_tag not in VOID_ELEMENTS:
                el.set("t-tag-close", el_tag)

        if not ({"t-out", "t-esc", "t-raw", "t-field"} & set(el.attrib)):
            el.set("t-inner-content", "True")

        return body + self._compile_directives(el, compile_context, level)

    def _compile_static_node(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile a purely static element into a list of string."""
        if not el.nsmap:
            unqualified_el_tag = el_tag = el.tag
            attrib = self._post_processing_att(
                el.tag, dict(el.attrib) | {"__is_static_node": True}
            )
        else:
            # Etree will remove the ns prefixes indirection by inlining the corresponding
            # nsmap definition into the tag attribute. Restore the tag and prefix here.
            unqualified_el_tag = etree.QName(el.tag).localname
            el_tag = unqualified_el_tag
            if el.prefix:
                el_tag = f"{el.prefix}:{el_tag}"

            attrib = {}
            # If `el` introduced new namespaces, write them as attribute by using the
            # `attrib` dict.
            for ns_prefix, ns_definition in set(el.nsmap.items()) - set(
                compile_context["nsmap"].items()
            ):
                if ns_prefix is None:
                    attrib["xmlns"] = ns_definition
                else:
                    attrib[f"xmlns:{ns_prefix}"] = ns_definition

            # Etree will also remove the ns prefixes indirection in the attributes. As we only have
            # the namespace definition, we'll use an nsmap where the keys are the definitions and
            # the values the prefixes in order to get back the right prefix and restore it.
            ns = chain(compile_context["nsmap"].items(), el.nsmap.items())
            nsprefixmap = {v: k for k, v in ns}
            for key, value in el.attrib.items():
                name = key.removesuffix(".translate")
                attrib_qname = etree.QName(name)
                if attrib_qname.namespace:
                    attrib[
                        f"{nsprefixmap[attrib_qname.namespace]}:{attrib_qname.localname}"
                    ] = value
                else:
                    attrib[name] = value

            attrib = self._post_processing_att(
                el.tag, attrib | {"__is_static_node": True}
            )

            # Update the dict of inherited namespaces before continuing the recursion. Note:
            # since `compile_context['nsmap']` is a dict (and therefore mutable) and we do **not**
            # want changes done in deeper recursion to be visible in earlier ones, we'll pass
            # a copy before continuing the recursion and restore the original afterwards.
            original_nsmap = dict(compile_context["nsmap"])

        if unqualified_el_tag != "t":
            attributes = "".join(
                f' {name.removesuffix(".translate")}="{escape(str(value))}"'
                for name, value in attrib.items()
                if value or isinstance(value, str)
            )
            self._append_text(f"<{el_tag}{''.join(attributes)}", compile_context)
            if el_tag in VOID_ELEMENTS:
                self._append_text("/>", compile_context)
            else:
                self._append_text(">", compile_context)

        el.attrib.clear()

        if el.nsmap:
            compile_context["nsmap"].update(el.nsmap)
            body = self._compile_directive(el, compile_context, "inner-content", level)
            compile_context["nsmap"] = original_nsmap
        else:
            body = self._compile_directive(el, compile_context, "inner-content", level)

        if unqualified_el_tag != "t":
            if el_tag not in VOID_ELEMENTS:
                self._append_text(f"</{el_tag}>", compile_context)

        return body

    def _compile_directives(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the given element, following the directives given in the
        iterator ``compile_context['iter_directives']`` created by
        ``_compile_node``.

        :return: list of code lines
        """
        if self._is_static_node(el, compile_context):
            el.attrib.pop("t-tag-open", None)
            el.attrib.pop("t-inner-content", None)
            el.attrib.pop("t-tag-close", None)
            return self._compile_static_node(el, compile_context, level)

        code = []

        # compile the directives still present on the element
        for directive in compile_context["iter_directives"]:
            if ("t-" + directive) in el.attrib:
                code.extend(
                    self._compile_directive(el, compile_context, directive, level)
                )
            elif directive == "groups":
                if directive in el.attrib:
                    code.extend(
                        self._compile_directive(el, compile_context, directive, level)
                    )
            elif directive == "att":
                code.extend(
                    self._compile_directive(el, compile_context, directive, level)
                )
            elif directive == "options":
                if any(name.startswith("t-options-") for name in el.attrib):
                    code.extend(
                        self._compile_directive(el, compile_context, directive, level)
                    )

        # compile unordered directives still present on the element
        for att in el.attrib:
            if (
                att not in SPECIAL_DIRECTIVES
                and att.startswith("t-")
                and getattr(
                    self,
                    f"_compile_directive_{att[2:].replace('-', '_')}",
                    None,
                )
            ):
                code.extend(
                    self._compile_directive(el, compile_context, att[2:], level)
                )

        remaining = set(el.attrib) - SPECIAL_DIRECTIVES
        if remaining:
            _logger.warning(
                "Unknown directives or unused attributes: %s in %s",
                remaining,
                compile_context["template"],
            )

        return code

    def _compile_directive(
        self,
        el: etree._Element,
        compile_context: dict[str, Any],
        directive: str,
        level: int,
    ) -> list[str]:
        compile_handler = getattr(
            self, f"_compile_directive_{directive.replace('-', '_')}", None
        )
        if compile_context.get("profile") and directive not in (
            "inner-content",
            "tag-open",
            "tag-close",
        ):
            enter = f"{' ' * 4 * level}self.env.context['qweb_tracker'].enter_directive({directive!r}, {el.attrib!r}, {compile_context['_qweb_error_path_xml'][1]!r})"
            leave = f"{' ' * 4 * level}self.env.context['qweb_tracker'].leave_directive({directive!r}, {el.attrib!r}, {compile_context['_qweb_error_path_xml'][1]!r})"
            code_directive = compile_handler(el, compile_context, level)
            if code_directive:
                code_directive = [enter, *code_directive, leave]
        else:
            code_directive = compile_handler(el, compile_context, level)
        return code_directive

    # compile directives

    def _compile_directive_debug(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-debug` expressions into a python code as a list of
        strings.

        The code will contains the call to the debugger chosen from the valid
        list.
        """
        debugger = el.attrib.pop("t-debug")
        code = []
        if compile_context.get("dev_mode"):
            code.append(indent_code(f"self._debug_trace({debugger!r}, values)", level))
        else:
            _logger.warning("@t-debug in template is only available in qweb dev mode")
        return code

    def _compile_directive_options(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile ``t-options`` and the ``t-options-*`` attributes, creating
        the ``values['__qweb_options__']`` dictionary in the compiled code.
        """
        code = []
        dict_options = []
        for key in list(el.attrib):
            if key.startswith("t-options-"):
                value = el.attrib.pop(key)
                option_name = key.removeprefix("t-options-")
                dict_options.append(f"{option_name!r}:{self._compile_expr(value)}")

        t_options = el.attrib.pop("t-options", None)
        if t_options and dict_options:
            code.append(
                indent_code(
                    f"values['__qweb_options__'] = {{**{self._compile_expr(t_options)}, {', '.join(dict_options)}}}",
                    level,
                )
            )
        elif dict_options:
            code.append(
                indent_code(
                    f"values['__qweb_options__'] = {{{', '.join(dict_options)}}}",
                    level,
                )
            )
        elif t_options:
            code.append(
                indent_code(
                    f"values['__qweb_options__'] = {self._compile_expr(t_options)}",
                    level,
                )
            )
        else:
            code.append(indent_code("values['__qweb_options__'] = {}", level))

        el.set("t-consumed-options", str(bool(code)))

        return code

    def _compile_directive_consumed_options(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        msg = "the t-options must be on the same tag as a directive that consumes it (for example: t-out, t-field, t-call)"
        raise SyntaxError(msg)

    def _compile_directive_att(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the attributes of the given element.

        The compiled function creates and fills the ``values['__qweb_attrs__']``
        dictionary (output later by the ``t-tag-open`` directive) with, in order:

        - the new namespaces introduced by the current element;
        - the static attributes (not prefixed by ``t-``);
        - the dynamic attributes:

          - ``t-att``: python dictionary expression;
          - ``t-att-*``: python expression;
          - ``t-attf-*``: format string expression.
        """
        code = [indent_code("attrs = values['__qweb_attrs__'] = {}", level)]

        # Compile the introduced new namespaces of the given element.
        #
        # Add the found new attributes into the `attrs` dictionary like
        # the static attributes.
        if el.nsmap:
            for ns_prefix, ns_definition in set(el.nsmap.items()) - set(
                compile_context["nsmap"].items()
            ):
                key = "xmlns"
                if ns_prefix is not None:
                    key = f"xmlns:{ns_prefix}"
                code.append(indent_code(f"attrs[{key!r}] = {ns_definition!r}", level))

        # Compile the static attributes of the given element.
        #
        # Etree will also remove the ns prefixes indirection in the
        # attributes. As we only have the namespace definition, we'll use
        # an nsmap where the keys are the definitions and the values the
        # prefixes in order to get back the right prefix and restore it.
        if any(not key.startswith("t-") for key in el.attrib):
            nsprefixmap = {
                v: k
                for k, v in chain(compile_context["nsmap"].items(), el.nsmap.items())
            }
            for key in list(el.attrib):
                if not key.startswith("t-"):
                    value = el.attrib.pop(key)
                    name = key.removesuffix(".translate")
                    attrib_qname = etree.QName(name)
                    if attrib_qname.namespace:
                        name = f"{nsprefixmap[attrib_qname.namespace]}:{attrib_qname.localname}"
                    code.append(indent_code(f"attrs[{name!r}] = {value!r}", level))

        # Compile the dynamic attributes of the given element. All
        # attributes will be add to the ``attrs`` dictionary in the
        # compiled function.
        for key in list(el.attrib):
            if key.startswith("t-attf-"):
                value = el.attrib.pop(key)
                name = key[7:].removesuffix(".translate")
                code.append(
                    indent_code(
                        f"attrs[{name!r}] = {self._compile_format(value)}",
                        level,
                    )
                )
            elif key.startswith("t-att-"):
                value = el.attrib.pop(key)
                code.append(
                    indent_code(
                        f"attrs[{key.removeprefix('t-att-')!r}] = {self._compile_expr(value)}",
                        level,
                    )
                )
            elif key == "t-att":
                value = el.attrib.pop(key)
                code.append(
                    indent_code(
                        f"""
                    atts_value = {self._compile_expr(value)}
                    if isinstance(atts_value, dict):
                        attrs.update(atts_value)
                    elif isinstance(atts_value, (list, tuple)) and atts_value and not isinstance(atts_value[0], (list, tuple)):
                        attrs.update([atts_value])
                    elif isinstance(atts_value, (list, tuple)):
                        attrs.update(dict(atts_value))
                    """,
                        level,
                    )
                )

        return code

    def _compile_directive_tag_open(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the opening tag of the given element into python code.

        The compiled function outputs the open tag, then post-processes and
        outputs the attributes from the ``attrs`` dictionary (built by the
        ``t-att`` directive), consuming and resetting it.
        """

        el_tag = el.attrib.pop("t-tag-open", None)
        if not el_tag:
            return []

        # open the open tag
        self._append_text(f"<{el_tag}", compile_context)

        code = self._flush_text(compile_context, level)

        # Generates the part of the code that prost process and output the
        # attributes from ``attrs`` dictionary. Consumes `attrs` dictionary
        # and reset it.
        #
        # Use str(value) to change Markup into str and escape it, then use str
        # to avoid the escaping of the other html content.
        code.append(
            indent_code(
                f"""
            attrs = values.pop('__qweb_attrs__', None)
            if attrs:
                tagName = {el.tag!r}
                attrs = self._post_processing_att(tagName, attrs)
                for name, value in attrs.items():
                    if value or isinstance(value, str):
                        yield f' {{escape(str(name))}}="{{escape(str(value))}}"'
        """,
                level,
            )
        )

        # close the open tag
        if "t-tag-close" in el.attrib:
            self._append_text(">", compile_context)
        else:
            self._append_text("/>", compile_context)

        return code

    def _compile_directive_tag_close(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the closing tag of the given element into string.
        Returns an empty list because it only uses ``_append_text``.
        """
        el_tag = el.attrib.pop("t-tag-close", None)
        if el_tag:
            self._append_text(f"</{el_tag}>", compile_context)
        return []

    def _compile_directive_set(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-set` expressions into a python code as a list of
        strings.

        There are different kinds of `t-set`:
        * `t-value` containing python code;
        * `t-valuef` containing strings to format;
        * `t-valuef.translate` containing translated strings to format;
        * whose value is the content of the tag (being Markup safe).

        The code will contain the assignment of the dynamically generated value.
        """

        code = self._flush_text(compile_context, level, rstrip=el.tag.lower() == "t")

        if "t-set" in el.attrib:
            varname = el.attrib.pop("t-set")
            if varname == "":
                msg = "t-set"
                raise KeyError(msg)
            if (
                varname != T_CALL_SLOT
                and varname[0] != "{"
                and not VARNAME_REGEXP.match(varname)
            ):
                msg = "The varname can only contain alphanumeric characters and underscores."
                raise SyntaxError(msg)
            if "__" in varname:
                raise SyntaxError(
                    f"Using variable names with '__' is not allowed: {varname!r}"
                )

            if (
                "t-value" in el.attrib
                or "t-valuef" in el.attrib
                or "t-valuef.translate" in el.attrib
                or varname[0] == "{"
            ):
                el.attrib.pop("t-inner-content")  # The content is considered empty.
                if varname == T_CALL_SLOT:
                    msg = 't-set="0" should not be set from t-value or t-valuef'
                    raise SyntaxError(msg)

            if "t-value" in el.attrib:
                expr = el.attrib.pop("t-value") or "None"
                code.append(
                    indent_code(
                        f"values[{varname!r}] = {self._compile_expr(expr)}",
                        level,
                    )
                )
            elif "t-valuef" in el.attrib:
                exprf = el.attrib.pop("t-valuef")
                code.append(
                    indent_code(
                        f"values[{varname!r}] = {self._compile_format(exprf)}",
                        level,
                    )
                )
            elif "t-valuef.translate" in el.attrib:
                exprf = el.attrib.pop("t-valuef.translate")
                if self.env.context.get("edit_translations"):
                    code.append(
                        indent_code(
                            f"values[{varname!r}] = Markup({self._compile_format(exprf)})",
                            level,
                        )
                    )
                else:
                    code.append(
                        indent_code(
                            f"values[{varname!r}] = {self._compile_format(exprf)}",
                            level,
                        )
                    )
            elif varname[0] == "{":
                code.append(
                    indent_code(f"values.update({self._compile_expr(varname)})", level)
                )
            else:
                # set the content as value
                _ref, path, xml = compile_context["_qweb_error_path_xml"]
                content = self._compile_directive(
                    el, compile_context, "inner-content", 1
                ) + self._flush_text(compile_context, 1)
                if content:
                    def_name = compile_context["make_name"]("t_set")
                    def_code = [f"def {def_name}(self, values):"]
                    def_code.append(indent_code(f"# element: {path!r} , {xml!r}", 1))
                    def_code.extend(content)
                    compile_context["template_functions"][def_name] = def_code

                    code.append(
                        indent_code(
                            f"""
                        values[{varname!r}] = QwebContent(self, QwebCallParameters(self.env.context, {compile_context["ref"]!r}, {def_name!r}, values.copy(), 'root', 't-set', (template_options['ref'], {path!r}, {xml!r})))
                    """,
                            level,
                        )
                    )
                else:
                    code.append(indent_code(f"values[{varname!r}] = ''", level))

        return code

    def _compile_directive_value(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-value` expressions into a python code as a list of strings.

        This method only checks that this attribute is on the same node as a
        `t-set` attribute.
        """
        msg = "t-value must be on the same node of t-set"
        raise SyntaxError(msg)

    def _compile_directive_valuef(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-valuef` expressions into a python code as a list of strings.

        This method only checks that this attribute is on the same node as a
        `t-set` attribute.
        """
        msg = "t-valuef must be on the same node of t-set"
        raise SyntaxError(msg)

    def _compile_directive_inner_content(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile the content of the element (the technical ``t-inner-content``
        directive created by QWeb) into python code as a list of strings.

        The code contains the text content of the node and the compiled code
        from the recursive ``_compile_node`` calls on its children.
        """
        el.attrib.pop("t-inner-content", None)

        if el.nsmap:
            # Update the dict of inherited namespaces before continuing the recursion. Note:
            # since `compile_context['nsmap']` is a dict (and therefore mutable) and we do **not**
            # want changes done in deeper recursion to be visible in earlier ones, we'll pass
            # a copy before continuing the recursion and restore the original afterwards.
            compile_context = dict(compile_context, nsmap=el.nsmap)

        if el.text is not None:
            self._append_text(el.text, compile_context)
        body = []
        for item in list(el):
            if isinstance(item, etree._Comment):
                if compile_context.get("preserve_comments"):
                    self._append_text(f"<!--{item.text}-->", compile_context)
                else:
                    # When removing a comment, strip trailing indentation
                    # (spaces/tabs) from the preceding text chunk if it's
                    # purely whitespace, so blank lines don't keep invisible
                    # trailing spaces.
                    text_concat = compile_context["_text_concat"]
                    if text_concat and text_concat[-1].isspace():
                        text_concat[-1] = text_concat[-1].rstrip(" \t")
                    # Comments removed from the DOM by _compile_directive_if
                    # (between t-if and t-else/t-elif) need their tail
                    # indentation stripped too, since the surrounding
                    # whitespace is no longer meaningful.
                    if item.getparent() is None and item.tail is not None:
                        tail = item.tail
                        if tail.isspace():
                            tail = tail.rstrip(" \t")
                        if tail:
                            self._append_text(tail, compile_context)
                        continue
            elif isinstance(item, etree._ProcessingInstruction):
                if compile_context.get("preserve_comments"):
                    self._append_text(f"<?{item.target} {item.text}?>", compile_context)
                else:
                    text_concat = compile_context["_text_concat"]
                    if text_concat and text_concat[-1].isspace():
                        text_concat[-1] = text_concat[-1].rstrip(" \t")
            else:
                body.extend(self._compile_node(item, compile_context, level))
            # comments can also contains tail text
            if item.tail is not None:
                self._append_text(item.tail, compile_context)
        return body

    def _compile_directive_if(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-if` expressions into a python code as a list of strings.

        The code will contain the condition `if`, `else` and `elif` part that
        wrap the rest of the compiled code of this element.
        """
        expr = el.attrib.pop("t-if", el.attrib.pop("t-elif", None))

        if not expr or not expr.strip():
            raise ValueError("t-if or t-elif expression should not be empty.")

        strip = self._rstrip_text(
            compile_context
        )  # the withspaces is visible only when display a content
        if el.tag.lower() == "t" and el.text and LSTRIP_REGEXP.search(el.text):
            strip = ""  # remove technical spaces
        code = self._flush_text(compile_context, level)

        code.append(indent_code(f"if {self._compile_expr(expr)}:", level))
        body = []
        if strip:
            self._append_text(strip, compile_context)
        body.extend(
            self._compile_directives(el, compile_context, level + 1)
            + self._flush_text(compile_context, level + 1, rstrip=True)
        )
        code.extend(body or [indent_code("pass", level + 1)])

        # Look for the else or elif conditions
        next_el = el.getnext()
        comments_to_remove = []
        while isinstance(next_el, etree._Comment):
            comments_to_remove.append(next_el)
            next_el = next_el.getnext()

        # If there is a t-else directive, the comment nodes are deleted
        # and the t-else or t-elif is validated.
        if next_el is not None and {"t-else", "t-elif"} & set(next_el.attrib):
            # Insert a flag to allow t-else or t-elif rendering.
            next_el.attrib["t-else-valid"] = "True"

            # remove comment node
            parent = el.getparent()
            for comment in comments_to_remove:
                parent.remove(comment)
            if el.tail and not el.tail.isspace():
                msg = "Unexpected non-whitespace characters between t-if and t-else directives"
                raise SyntaxError(msg)
            el.tail = None

            # You have to render the `t-else` and `t-elif` here in order
            # to be able to put the log. Otherwise, the parent's
            # `t-inner-content`` directive will render the different
            # nodes without taking indentation into account such as:
            #    if (if_expression):
            #         content_if
            #    log ['last_path_node'] = path
            #    else:
            #       content_else

            code.append(indent_code("else:", level))
            body = []
            if strip:
                self._append_text(strip, compile_context)
            body.extend(
                self._compile_node(next_el, compile_context, level + 1)
                + self._flush_text(compile_context, level + 1, rstrip=True)
            )
            code.extend(body or [indent_code("pass", level + 1)])

            # Insert a flag to avoid the t-else or t-elif rendering when
            # the parent t-inner-content dirrective compile his
            # children.
            next_el.attrib["t-qweb-skip"] = "True"

        return code

    def _compile_directive_elif(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-elif` expressions into a python code as a list of
        strings. This method is linked with the `t-if` directive.

        Validate that this node follows a `t-if`/`t-elif` (the t-else-valid
        flag) and delegate to the `t-if` compilation.
        """
        if not el.attrib.pop("t-else-valid", None):
            msg = "t-elif directive must be preceded by t-if or t-elif directive"
            raise SyntaxError(msg)

        return self._compile_directive_if(el, compile_context, level)

    def _compile_directive_else(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-else` expressions into a python code as a list of strings.
        This method is linked with the `t-if` directive.

        Validate that this node follows a `t-if`/`t-elif` (the t-else-valid
        flag); produces no code of its own.
        """
        if not el.attrib.pop("t-else-valid", None):
            msg = "t-else directive must be preceded by t-if or t-elif directive"
            raise SyntaxError(msg)
        el.attrib.pop("t-else")
        return []

    def _compile_directive_groups(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-groups` expressions into a python code as a list of
        strings.

        The code will contain the condition `if self.env.user.has_groups(groups)`
        part that wrap the rest of the compiled code of this element.
        """
        groups = el.attrib.pop("t-groups", el.attrib.pop("groups", None))

        strip = self._rstrip_text(compile_context)
        code = self._flush_text(compile_context, level)
        code.append(indent_code(f"if self.env.user.has_groups({groups!r}):", level))
        if strip and el.tag.lower() != "t":
            self._append_text(strip, compile_context)
        code.extend(
            [
                *self._compile_directives(el, compile_context, level + 1),
                *self._flush_text(compile_context, level + 1, rstrip=True),
            ]
            or [indent_code("pass", level + 1)]
        )
        return code

    def _compile_directive_foreach(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile ``t-foreach`` expressions into a python code as a list of
        strings.

        * ``t-as`` is used to define the key name.
        * ``t-foreach`` compiled value can be an iterable, a dictionary or a
          number.

        The code will contain a ``for`` loop that wraps the rest of the compiled
        code of this element.

        Some keys in the values dictionary are created automatically::

            *_size, *_index, *_value, *_first, *_last, *_odd, *_even, *_parity
        """
        expr_foreach = el.attrib.pop("t-foreach")
        expr_as = el.attrib.pop("t-as")

        if not expr_as:
            msg = "t-as"
            raise KeyError(msg)

        if not VARNAME_REGEXP.match(expr_as):
            raise ValueError(
                f"The varname {expr_as!r} can only contain alphanumeric characters and underscores."
            )

        if el.tag.lower() == "t":
            self._rstrip_text(compile_context)

        code = self._flush_text(compile_context, level)

        content_foreach = self._compile_directives(
            el, compile_context, level + 1
        ) + self._flush_text(compile_context, level + 1, rstrip=True)

        t_foreach = compile_context["make_name"]("t_foreach")
        size = compile_context["make_name"]("size")
        has_value = compile_context["make_name"]("has_value")

        if expr_foreach.isdigit():
            code.append(
                indent_code(
                    f"""
                values[{expr_as + "_size"!r}] = {size} = {int(expr_foreach)}
                {t_foreach} = range({size})
                {has_value} = False
            """,
                    level,
                )
            )
        else:
            code.append(
                indent_code(
                    f"""
                {t_foreach} = {self._compile_expr(expr_foreach)} or []
                if isinstance({t_foreach}, Sized):
                    values[{expr_as + "_size"!r}] = {size} = len({t_foreach})
                elif ({t_foreach}).__class__ == int:
                    values[{expr_as + "_size"!r}] = {size} = {t_foreach}
                    {t_foreach} = range({size})
                else:
                    {size} = None
                {has_value} = False
                if isinstance({t_foreach}, Mapping):
                    {t_foreach} = {t_foreach}.items()
                    {has_value} = True
            """,
                    level,
                )
            )

        code.append(
            indent_code(
                f"""
                for index, item in enumerate({t_foreach}):
                    values[{expr_as + "_index"!r}] = index
                    if {has_value}:
                        values[{expr_as!r}], values[{expr_as + "_value"!r}] = item
                    else:
                        values[{expr_as!r}] = values[{expr_as + "_value"!r}] = item
                    values[{expr_as + "_first"!r}] = values[{expr_as + "_index"!r}] == 0
                    if {size} is not None:
                        values[{expr_as + "_last"!r}] = index + 1 == {size}
                    values[{expr_as + "_odd"!r}] = index % 2
                    values[{expr_as + "_even"!r}] = not values[{expr_as + "_odd"!r}]
                    values[{expr_as + "_parity"!r}] = 'odd' if values[{expr_as + "_odd"!r}] else 'even'
            """,
                level,
            )
        )

        code.extend(content_foreach or indent_code("continue", level + 1))

        return code

    def _compile_directive_as(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-as` expressions into a python code as a list of strings.

        This method only checks that this attribute is on the same node as a
        `t-foreach` attribute.
        """
        if "t-foreach" not in el.attrib:
            msg = "t-as must be on the same node of t-foreach"
            raise SyntaxError(msg)
        return []

    def _compile_directive_out(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-out` expressions into a python code as a list of
        strings.

        The code will contain evaluation and rendering of the compiled value. If
        the compiled value is None or False, the tag is not added to the render
        (Except if the widget forces rendering or there is default content).
        (eg: `<t t-out="my_value">Default content if falsy</t>`)

        The output can have some rendering option with `t-options-widget` or
        `t-options={'widget': ...}. At rendering time, The compiled code will
        call ``_get_widget`` method or ``_get_field`` method for `t-field`.

        A `t-field` will necessarily be linked to the value of a record field
        (eg: `<span t-field="record.field_name"/>`), a t-out` can be applied
        to any value (eg: `<span t-out="10" t-options-widget="'float'"/>`).
        """
        ttype = "t-out"
        expr = el.attrib.pop("t-out", None)
        if expr is None:
            ttype = "t-field"
            expr = el.attrib.pop("t-field", None)
            if expr is None:
                # deprecated use.
                ttype = "t-esc"
                expr = el.attrib.pop("t-esc", None)
                if expr is None:
                    ttype = "t-raw"
                    expr = el.attrib.pop("t-raw")

        code = self._flush_text(compile_context, level)

        _ref, path, xml = compile_context["_qweb_error_path_xml"]

        code_options = el.attrib.pop("t-consumed-options", "None")
        tag_open = self._compile_directive(
            el, compile_context, "tag-open", level + 1
        ) + self._flush_text(compile_context, level + 1)
        tag_close = self._compile_directive(
            el, compile_context, "tag-close", level + 1
        ) + self._flush_text(compile_context, level + 1)
        default_body = self._compile_directive(
            el, compile_context, "inner-content", level + 1
        ) + self._flush_text(compile_context, level + 1)

        # The generated code will set the values of the content, attrs (used to
        # output attributes) and the force_display (if the widget or field
        # mark force_display as True, the tag will be inserted in the output
        # even the value of content is None and without default value)

        if expr == T_CALL_SLOT and code_options != "True":
            code.append(indent_code("if True:", level))
            code.extend(tag_open)
            code.append(indent_code(f"yield values.get({T_CALL_SLOT}, '')", level + 1))
            code.extend(tag_close)
            return code
        elif ttype == "t-field":
            record, field_name = expr.rsplit(".", 1)
            code.append(
                indent_code(
                    f"""
                field_attrs, content, force_display = self._get_field({self._compile_expr(record, raise_on_missing=True)}, {field_name!r}, {expr!r}, {el.tag!r}, values.pop('__qweb_options__', {{}}), values)
                if values.get('__qweb_attrs__') is None:
                    values['__qweb_attrs__'] = field_attrs
                else:
                    values['__qweb_attrs__'].update(field_attrs)
                if content is not None and content is not False:
                    content = self._compile_to_str(content)
                """,
                    level,
                )
            )
            force_display_dependent = True
        else:
            if expr == T_CALL_SLOT:
                code.append(
                    indent_code(f"content = values.get({T_CALL_SLOT}, '')", level)
                )
            else:
                code.append(indent_code(f"content = {self._compile_expr(expr)}", level))

            if code_options == "True":
                code.append(
                    indent_code(
                        f"""
                    widget_attrs, content, force_display = self._get_widget(content, {expr!r}, {el.tag!r}, values.pop('__qweb_options__', {{}}), values)
                    if values.get('__qweb_attrs__') is None:
                        values['__qweb_attrs__'] = widget_attrs
                    else:
                        values['__qweb_attrs__'].update(widget_attrs)
                    content = self._compile_to_str(content)
                    """,
                        level,
                    )
                )
                force_display_dependent = True
            else:
                force_display_dependent = False

            if ttype == "t-raw":
                # deprecated use.
                code.append(
                    indent_code(
                        """
                    if content is not None and content is not False:
                        content = Markup(content)
                """,
                        level,
                    )
                )

        # The generated code will create the output tag with all attribute.
        # If the value is not falsy or if there is default content or if it's
        # in force_display mode, the tag is add into the output.

        el.attrib.pop("t-tag", None)  # code generating the output is done here

        # generate code to display the tag if the value is not Falsy

        code.append(
            indent_code("if content is not None and content is not False:", level)
        )
        code.extend(tag_open)
        # Use str to avoid the escaping of the other html content because the
        # yield generator MarkupSafe values will be join into an string in
        # `_render`.
        code.append(
            indent_code(
                f"""
            if isinstance(content, QwebContent):
                self.env.context['_qweb_error_path_xml'][0] = template_options['ref']
                self.env.context['_qweb_error_path_xml'][1] = {path!r}
                self.env.context['_qweb_error_path_xml'][2] = {xml!r}
                yield content
            else:
                yield str(escape(content))
        """,
                level + 1,
            )
        )
        code.extend(tag_close)

        # generate code to display the tag with default content if the value is
        # Falsy

        if default_body or compile_context["_text_concat"]:
            _text_concat = list(compile_context["_text_concat"])
            compile_context["_text_concat"].clear()
            code.append(indent_code("else:", level))
            code.extend(tag_open)
            code.extend(default_body)
            compile_context["_text_concat"].extend(_text_concat)
            code.extend(tag_close)
        elif force_display_dependent:
            # generate code to display the tag if it's the force_diplay mode.

            if tag_open + tag_close:
                code.append(indent_code("elif force_display:", level))
                code.extend(tag_open + tag_close)

            code.append(
                indent_code("""else: values.pop('__qweb_attrs__', None)""", level)
            )

        return code

    def _compile_directive_esc(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        # deprecated use.
        if compile_context.get("dev_mode"):
            _logger.warning(
                "Found deprecated directive @t-esc=%r in template %r. Replace by @t-out",
                el.get("t-esc"),
                compile_context.get("ref", "<unknown>"),
            )
        return self._compile_directive_out(el, compile_context, level)

    def _compile_directive_raw(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        # deprecated use.
        _logger.warning(
            "Found deprecated directive @t-raw=%r in template %r. Replace by "
            "@t-out, and explicitely wrap content in `Markup` if "
            "necessary (which likely is not the case)",
            el.get("t-raw"),
            compile_context.get("ref", "<unknown>"),
        )
        return self._compile_directive_out(el, compile_context, level)

    def _compile_directive_field(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile ``t-field`` expressions into a python code as a list of
        strings.

        The compiled code will call ``_get_field`` method at rendering time
        using the type of value supplied by the field. This behavior can be
        changed with ``t-options-widget`` or ``t-options={'widget': ...}``.

        The code will contain evaluation and rendering of the compiled value
        from the record field. If the compiled value is None or False,
        the tag is not added to the render
        (Except if the widget forces rendering or there is default content.).
        """
        tagName = el.tag
        _FORBIDDEN_FIELD_TAGS = {
            "table",
            "tbody",
            "thead",
            "tfoot",
            "tr",
            "td",
            "li",
            "ul",
            "ol",
            "dl",
            "dt",
            "dd",
        }
        if tagName in _FORBIDDEN_FIELD_TAGS:
            raise ValueError(
                "QWeb widgets do not work correctly on %r elements" % tagName
            )
        if tagName == "t":
            raise ValueError(
                "t-field can not be used on a t element, provide an actual HTML node"
            )
        if "." not in (el.get("t-field") or ""):
            raise ValueError(
                "t-field must have at least a dot like 'record.field_name'"
            )

        return self._compile_directive_out(el, compile_context, level)

    def _compile_directive_call(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """Compile `t-call` expressions into a python code as a list of
        strings.

        `t-call` allows formatting strings dynamically at rendering time.
        Can use `t-options` used to call and render the sub-template at
        rendering time.
        The sub-template is called with a copy of the rendering values
        dictionary. The dictionary contains the key 0 coming from the
        compilation of the contents of this element

        The code will contain the call of the template and a function from the
        compilation of the content of this element.
        """
        expr = el.attrib.pop("t-call")

        el_tag = etree.QName(el.tag).localname if el.nsmap else el.tag
        if el_tag != "t":
            raise SyntaxError(
                f"t-call must be on a <t> element (actually on <{el_tag}>)."
            )

        if el.attrib.get("t-call-options"):  # retro-compatibility
            # lxml's _Attrib has no .set() method; assign via item access.
            # el.attrib.set(...) would raise AttributeError on this (latent)
            # retro-compat path.
            el.attrib["t-options"] = el.attrib.pop("t-call-options")

        nsmap = compile_context.get("nsmap")

        code = self._flush_text(compile_context, level, rstrip=el.tag.lower() == "t")
        _ref, path, xml = compile_context["_qweb_error_path_xml"]

        # options
        el.attrib.pop("t-consumed-options", None)
        code.append(
            indent_code("t_call_options = values.pop('__qweb_options__', {})", level)
        )
        if nsmap:
            # update this dict with the current nsmap so that the callee know
            # if he outputting the xmlns attributes is relevenat or not
            nsmap = []
            for key, value in compile_context["nsmap"].items():
                if isinstance(key, str):
                    nsmap.append(f"{key!r}:{value!r}")
                else:
                    nsmap.append(f"None:{value!r}")
            code.append(
                indent_code(
                    f"t_call_options.update(nsmap={{{', '.join(nsmap)}}})",
                    level,
                )
            )

        # values from content (t-out="0")
        if bool(list(el) or el.text):
            is_deprecated_version = not any(
                not key.startswith("t-") for key in el.attrib
            ) and any(n.attrib.get("t-set") for n in el)

            def_name = compile_context["make_name"]("t_call")
            code_content = [f"def {def_name}(self, values):"]
            code_content.append(indent_code(f"# element: {path!r} , {xml!r}", 1))
            code_content.extend(
                self._compile_directive(el, compile_context, "inner-content", 1)
            )
            self._append_text(
                "", compile_context
            )  # To ensure the template function is a generator and doesn't become a regular function
            code_content.extend(self._flush_text(compile_context, 1, rstrip=True))

            compile_context["template_functions"][def_name] = code_content

            code.append(
                indent_code(
                    f"""
                t_call_content_values = values.copy()
                qwebContent = QwebContent(self, QwebCallParameters(self.env.context, {compile_context["ref"]!r}, {def_name!r}, t_call_content_values, 'root', 'inner-content', (template_options['ref'], {path!r}, {xml!r})))
                t_call_values = {{ {T_CALL_SLOT}: qwebContent}}
            """,
                    level,
                )
            )

            if is_deprecated_version:
                # force the loading of the content to get values from t-set
                code.append(
                    indent_code(
                        f"""
                    str(qwebContent)
                    new_values = {{k: v for k, v in t_call_content_values.items() if k != {T_CALL_SLOT} and k != '__qweb_attrs__' and values.get(k) is not v}}
                    t_call_values.update(new_values)
                """,
                        level,
                    )
                )
        else:
            code.append(indent_code(f"t_call_values = {{ {T_CALL_SLOT}: '' }}", level))

        # args to values
        for key in list(el.attrib):
            if key.endswith(".f"):
                name = key.removesuffix(".f")
                value = el.attrib.pop(key)
                code.append(
                    indent_code(
                        f"t_call_values[{name!r}] = {self._compile_format(value)}",
                        level,
                    )
                )
            elif key.endswith(".translate"):
                name = key.removesuffix(".f").removesuffix(".translate")
                value = el.attrib.pop(key)
                if self.env.context.get("edit_translations"):
                    code.append(
                        indent_code(
                            f"t_call_values[{name!r}] = Markup({self._compile_format(value)})",
                            level,
                        )
                    )
                else:
                    code.append(
                        indent_code(
                            f"t_call_values[{name!r}] = {self._compile_format(value)}",
                            level,
                        )
                    )
            elif not key.startswith("t-"):
                value = el.attrib.pop(key)
                code.append(
                    indent_code(
                        f"t_call_values[{key!r}] = {self._compile_expr(value)}",
                        level,
                    )
                )
            elif key == "t-args":
                value = el.attrib.pop(key)
                code.append(
                    indent_code(
                        f"""
                    atts_value = {self._compile_expr(value)}
                    if isinstance(atts_value, dict):
                        t_call_values.update(atts_value)
                    elif isinstance(atts_value, (list, tuple)) and atts_value and not isinstance(atts_value[0], (list, tuple)):
                        t_call_values.update([atts_value])
                    elif isinstance(atts_value, (list, tuple)):
                        t_call_values.update(dict(atts_value))
                    """,
                        level,
                    )
                )

        template = expr if expr.isnumeric() else self._compile_format(expr)

        # call
        code.append(
            indent_code(
                f"""
            template = {template}
            """,
                level,
            )
        )
        if "%" in template:
            code.append(
                indent_code(
                    """
                if template.isnumeric():
                    template = int(template)
                """,
                    level,
                )
            )

        code.append(
            indent_code(
                f"yield QwebCallParameters(t_call_options, template, None, t_call_values, True, 't-call', (template_options['ref'], {path!r}, {xml!r}))",
                level,
            )
        )

        return code

    def _compile_directive_lang(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        if "t-call" not in el.attrib:
            msg = "t-lang is an alias of t-options-lang but only available on the same node of t-call"
            raise SyntaxError(msg)
        el.attrib["t-options-lang"] = el.attrib.pop("t-lang")
        return self._compile_node(el, compile_context, level)

    def _compile_directive_call_assets(
        self, el: etree._Element, compile_context: dict[str, Any], level: int
    ) -> list[str]:
        """This special 't-call-assets' tag can be used in order to aggregate/minify javascript and css assets"""
        if len(el) > 0:
            msg = "t-call-assets cannot contain children nodes"
            raise SyntaxError(msg)

        code = self._flush_text(compile_context, level)
        xmlid = el.attrib.pop("t-call-assets")
        css = self._compile_bool(el.attrib.pop("t-css", True))
        js = self._compile_bool(el.attrib.pop("t-js", True))
        # async_load support was removed
        defer_load = self._compile_bool(el.attrib.pop("defer_load", False))
        lazy_load = self._compile_bool(el.attrib.pop("lazy_load", False))
        media = el.attrib.pop("media", False)
        autoprefix = self._compile_bool(el.attrib.pop("t-autoprefix", False))
        code.append(
            indent_code(
                f"""
            t_call_assets_nodes = self._get_asset_nodes(
                {xmlid!r},
                css={css},
                js={js},
                debug=values.get("debug"),
                defer_load={defer_load},
                lazy_load={lazy_load},
                media={media!r},
                autoprefix={autoprefix}
            )
        """.strip(),
                level,
            )
        )

        code.append(
            indent_code(
                """
            for index, (tagName, asset_attrs) in enumerate(t_call_assets_nodes):
                if index:
                    yield '\\n        '
                yield '<'
                yield tagName

                # Extract inline text content (import maps, loader shim, bridge
                # scripts) WITHOUT mutating asset_attrs: these node dicts are
                # served straight from the ormcache (_get_native_module_nodes_cached),
                # so a .pop() permanently strips 'text' from the cached copy and
                # every render after the first emits an empty <script>. Read with
                # .get and pass a 'text'-free copy to attribute post-processing.
                text_content = asset_attrs.get("text") if asset_attrs else None
                attrs = self._post_processing_att(
                    tagName,
                    {k: v for k, v in asset_attrs.items() if k != "text"}
                    if asset_attrs
                    else {},
                )
                for name, value in attrs.items():
                    if value or isinstance(value, str):
                        yield f' {escape(str(name))}="{escape(str(value))}"'

                if tagName in VOID_ELEMENTS:
                    yield '/>'
                else:
                    yield '>'
                    if text_content:
                        yield str(text_content)
                    yield '</'
                    yield tagName
                    yield '>'
                """,
                level,
            )
        )

        return code

    # methods called by the compiled function at rendering time.

    def _debug_trace(self, debugger: str, values: dict[str, Any]) -> None:
        """Method called at running time to load debugger."""
        if not debugger:
            breakpoint()  # noqa: T100
        elif debugger in SUPPORTED_DEBUGGER:
            warnings.warn(
                "Using t-debug with an explicit debugger is deprecated "
                "since Odoo 17.0, keep the value empty and configure the "
                "``breakpoint`` builtin instead.",
                category=DeprecationWarning,
                stacklevel=2,
            )
            __import__(debugger).set_trace()
        else:
            raise ValueError(f"unsupported t-debug value: {debugger}")

    def _post_processing_att(
        self, tagName: str, atts: dict[str, Any]
    ) -> dict[str, Any]:
        """Method called at compile time for static nodes and at running time
        for dynamic attributes.

        May be overridden to filter or modify the attributes (during compilation
        for static nodes, or after compilation for dynamic elements).

        :rtype: dict
        """
        if not atts.pop("__is_static_node", False):
            for attr in ("href", "src", "action", "formaction"):
                if (value := atts.get(attr)) and MALICIOUS_SCHEMES(
                    URL_CONTROL_CHARS.sub("", str(value))
                ):
                    atts[attr] = ""
        return atts

    def _get_field(
        self,
        record: models.BaseModel,
        field_name: str,
        expression: str,
        tagName: str,
        field_options: dict[str, Any],
        values: dict[str, Any],
    ) -> tuple[dict[str, Any], str | Markup | bool | None, bool]:
        """Method called at rendering time to return the field value.

        :returns: tuple:
            * dict: attributes
            * string or None: content
            * boolean: force_display display the tag if the content and default_content are None
        """
        field = record._fields[field_name]

        # adds generic field options
        field_options["tagName"] = tagName
        field_options["expression"] = expression
        field_options["type"] = field_options.get("widget", field.type)
        inherit_branding = (
            self.env.context["inherit_branding"]
            if "inherit_branding" in self.env.context
            else self.env.context.get("inherit_branding_auto")
            and record.has_access("write")
        )
        field_options["inherit_branding"] = inherit_branding
        translate = (
            self.env.context.get("edit_translations")
            and values.get("translatable")
            and field.translate
        )
        field_options["translate"] = translate

        # field converter
        model = "ir.qweb.field." + field_options["type"]
        converter = self.env[model] if model in self.env else self.env["ir.qweb.field"]

        # get content (the return values from fields are considered to be markup safe)
        content = converter.record_to_html(record, field_name, field_options)
        attributes = converter.attributes(record, field_name, field_options, values)

        return (attributes, content, inherit_branding or translate)

    def _get_widget(
        self,
        value: Any,
        expression: str,
        tagName: str,
        field_options: dict[str, Any],
        values: dict[str, Any],
    ) -> tuple[dict[str, Any], str | Markup | bool | None, bool | None]:
        """Method called at rendering time to return the widget value.

        :returns: tuple:
            * dict: attributes
            * string or None: content
            * boolean: force_display display the tag if the content and default_content are None
        """
        field_options["type"] = field_options["widget"]
        field_options["tagName"] = tagName
        field_options["expression"] = expression
        inherit_branding = self.env.context.get("inherit_branding")
        field_options["inherit_branding"] = inherit_branding

        # field converter
        model = "ir.qweb.field." + field_options["type"]
        converter = self.env[model] if model in self.env else self.env["ir.qweb.field"]

        # get content (the return values from widget are considered to be markup safe)
        content = converter.value_to_html(value, field_options)
        attributes = {}
        attributes["data-oe-type"] = field_options["type"]
        attributes["data-oe-expression"] = field_options["expression"]

        return (attributes, content, inherit_branding)

    def _get_asset_nodes(
        self,
        bundle: str,
        css: bool = True,
        js: bool = True,
        debug: str | bool = False,
        defer_load: bool = False,
        lazy_load: bool = False,
        media: str | None = None,
        autoprefix: bool = False,
    ) -> list[tuple[str, dict[str, Any]]]:
        """Generates asset nodes.
        If debug=assets, the assets will be regenerated when a file which composes them has been modified.
        Else, the assets will be generated only once and then stored in cache.

        When native ESM modules are present (``@odoo-module native``), the output
        includes an import map and a bridge ``<script type="module">`` that
        pre-registers them before the legacy bundle executes.  The legacy bundle
        gets ``defer`` to guarantee correct execution order.
        """
        media = (css and media) or None
        links = self._get_asset_links(
            bundle, css=css, js=js, debug=debug, autoprefix=autoprefix
        )

        # Check for native ESM modules in this bundle
        pre_nodes = []
        post_nodes = []
        has_native = False
        if js:
            pre_nodes, post_nodes = self._get_native_module_nodes(
                bundle,
                debug=debug,
            )
            # ``has_native`` indicates that native-ESM rendering happened.
            # Either pre_nodes (importmap, shim, modulepreload) or
            # post_nodes (bridge, templates) being non-empty means the
            # bundle's ESM contribution has to be returned alongside
            # the legacy links — secondary bundles (whose import map and
            # shim are skipped because the parent already rendered them)
            # may have only post_nodes, and dropping them silently would
            # leave their bridge code unrendered in the final HTML.
            has_native = bool(pre_nodes) or bool(post_nodes)

        # Classic scripts (Bootstrap, Luxon, etc.) must NOT be deferred when
        # native ESM modules are present — they set UMD globals that native
        # modules access at module scope.  Non-deferred scripts execute during
        # parsing, BEFORE any <script type="module"> scripts, guaranteeing
        # that globals like `luxon`, `Tooltip`, `Dropdown` are available.
        nodes = self._links_to_nodes(
            links,
            defer_load=defer_load,
            lazy_load=lazy_load,
            media=media,
        )

        log_event(
            _esm_log,
            logging.DEBUG,
            "nodes",
            bundle=bundle,
            debug=bool(debug),
            css=css,
            js=js,
            links=len(nodes),
            pre=len(pre_nodes),
            post=len(post_nodes),
            native=has_native,
        )
        if has_native:
            return pre_nodes + nodes + post_nodes

        return nodes

    def _get_asset_links(
        self,
        bundle: str,
        css: bool = True,
        js: bool = True,
        debug: str | bool | None = None,
        autoprefix: bool = False,
    ) -> list[str]:
        """Generates asset links (URLs), not nodes.
        If debug=assets, the assets will be regenerated when a file which composes them has been modified.
        Else, the assets will be generated only once and then stored in cache.
        """
        rtl = (
            self.env["res.lang"]
            .sudo()
            ._get_data(code=(self.env.lang or self.env.user.lang))
            .direction
            == "rtl"
        )
        assets_params = self.env["ir.asset"]._get_asset_params()  # website_id
        debug_assets = debug and "assets" in debug

        if debug_assets:
            return self._generate_asset_links(
                bundle,
                css=css,
                js=js,
                debug_assets=True,
                assets_params=assets_params,
                rtl=rtl,
                autoprefix=autoprefix,
            )
        else:
            return self._generate_asset_links_cache(
                bundle,
                css=css,
                js=js,
                assets_params=assets_params,
                rtl=rtl,
                autoprefix=autoprefix,
            )

    # other methods used for the asset bundles
    @tools.conditional(
        # in non-xml-debug mode we want assets to be cached forever, and the admin can force a cache clear
        # by restarting the server after updating the source code (or using the "Clear server cache" in debug tools)
        "xml" not in tools.config["dev_mode"],
        tools.ormcache(
            "bundle",
            "css",
            "js",
            "tuple(sorted(assets_params.items()))",
            "rtl",
            "autoprefix",
            cache="assets",
        ),
    )
    def _generate_asset_links_cache(
        self,
        bundle: str,
        css: bool = True,
        js: bool = True,
        assets_params: dict[str, Any] | None = None,
        rtl: bool = False,
        autoprefix: bool = False,
    ) -> list[str]:
        return self._generate_asset_links(
            bundle, css, js, False, assets_params, rtl, autoprefix=autoprefix
        )

    def _get_asset_content(
        self, bundle: str, assets_params: dict[str, Any] | None = None
    ) -> tuple[list[BundleFileSpec], list[str]]:
        if assets_params is None:
            assets_params = self.env["ir.asset"]._get_asset_params()  # website_id
        asset_paths = self.env["ir.asset"]._get_asset_paths(
            bundle=bundle, assets_params=assets_params
        )
        files = []
        external_asset = []
        for path, full_path, _bundle, last_modified in asset_paths:
            if full_path is not EXTERNAL_ASSET:
                files.append(
                    {
                        "url": path,
                        "filename": full_path,
                        "content": "",
                        "last_modified": last_modified,
                    }
                )
            else:
                external_asset.append(path)
        return (files, external_asset)

    def _get_asset_bundle(
        self,
        bundle_name: str,
        css: bool = True,
        js: bool = True,
        debug_assets: bool = False,
        rtl: bool = False,
        assets_params: dict[str, Any] | None = None,
        autoprefix: bool = False,
    ) -> AssetsBundle:
        if assets_params is None:
            assets_params = self.env["ir.asset"]._get_asset_params()
        files, external_assets = self._get_asset_content(bundle_name, assets_params)
        return AssetsBundle(
            bundle_name,
            files,
            external_assets,
            env=self.env,
            css=css,
            js=js,
            debug_assets=debug_assets,
            rtl=rtl,
            assets_params=assets_params,
            autoprefix=autoprefix,
        )

    def _links_to_nodes(
        self,
        paths: list[str],
        defer_load: bool = False,
        lazy_load: bool = False,
        media: str | None = None,
    ) -> list[tuple[str, dict[str, Any]]]:
        # ``_link_to_node`` returns None for a path whose extension is not a
        # known script/style/template type (e.g. an external URL with a query
        # string). Drop those: downstream consumers (the generated
        # ``t-call-assets`` loop) unpack ``(tagName, attrs)`` directly and would
        # raise TypeError on a None. Log dropped paths so a misclassified asset
        # is visible instead of silently missing from the page.
        nodes = []
        for path in paths:
            node = self._link_to_node(
                path, defer_load=defer_load, lazy_load=lazy_load, media=media
            )
            if node is None:
                _logger.warning(
                    "Asset path %r has no renderable node (unrecognized extension); skipped.",
                    path,
                )
                continue
            nodes.append(node)
        return nodes

    def _link_to_node(
        self,
        path: str,
        defer_load: bool = False,
        lazy_load: bool = False,
        media: str | None = None,
    ) -> tuple[str, dict[str, Any]] | None:
        ext = path.rsplit(".", maxsplit=1)[-1] if path else "js"
        is_js = ext in SCRIPT_EXTENSIONS
        is_xml = ext in TEMPLATE_EXTENSIONS
        is_css = ext in STYLE_EXTENSIONS

        if is_js:
            attributes = {
                "type": "text/javascript",
            }

            if defer_load:
                # Note that "lazy_load" will lead to "defer" being added in JS,
                # not here, otherwise this is not W3C valid (defer is probably
                # not even needed there anyways). See LAZY_LOAD_DEFER.
                attributes["defer"] = "defer"
            if path:
                if lazy_load:
                    attributes["data-src"] = path
                else:
                    attributes["src"] = path

            # NOTE: bundle scripts used to carry ``onerror="__odooAssetError=1"``
            # — a vestige of a removed reload mechanism; no runtime reader
            # existed.  Load-failure self-healing now lives in the module
            # loader shim (``module_loader.js`` captures script error events
            # for ``/web/assets/`` URLs and triggers one guarded reload).
            return ("script", attributes)

        if is_css:
            attributes = {
                "type": f"text/{ext}",  # we don't really expect to have anything else than pure css here
                "rel": "stylesheet",
                "href": path,
                "media": media,
            }
            return ("link", attributes)

        if is_xml:
            attributes = {
                "type": "text/xml",
                "async": "async",
                "rel": "prefetch",
                "data-src": path,
            }
            return ("script", attributes)

        return None

    def _generate_asset_links(
        self,
        bundle: str,
        css: bool = True,
        js: bool = True,
        debug_assets: bool = False,
        assets_params: dict[str, Any] | None = None,
        rtl: bool = False,
        autoprefix: bool = False,
    ) -> list[str]:
        asset_bundle = self._get_asset_bundle(
            bundle,
            css=css,
            js=js,
            debug_assets=debug_assets,
            rtl=rtl,
            assets_params=assets_params,
            autoprefix=autoprefix,
        )
        return asset_bundle.get_links()

    # URL of the OWL ESM library — real ESM build, loaded via import map
    _OWL_ESM_URL = "/web/static/lib/owl/owl.es.js"
    # Import-map entries for esbuild-externalized libraries.  The
    # canonical definition lives in ``odoo.libs.constants`` so that
    # ``assetsbundle`` can read it without importing this module (the
    # two used to form an import cycle patched with a deferred import);
    # the class alias keeps the ``self._ODOO_EXTERNAL_LIBS`` read sites.
    _ODOO_EXTERNAL_LIBS = ODOO_EXTERNAL_LIBS

    @staticmethod
    def _specifier_to_static_url(spec: str) -> str | None:
        """Resolve an ``@addon/path`` specifier to a served static URL.

        Follows Odoo's bundling convention:
          * ``@web/core/registry``       → ``/web/static/src/core/registry.js``
          * ``@web/../lib/hoot/hoot``    → ``/web/static/lib/hoot/hoot.js``
          * ``@web/../tests/foo``        → ``/web/static/tests/foo.js``

        Returns ``None`` for specifiers that don't match the convention
        (e.g. bare ``luxon``, ``@odoo/owl``) — those belong in
        ``_ODOO_EXTERNAL_LIBS`` or esbuild aliases instead.
        """
        if not spec.startswith("@"):
            return None
        rest = spec[1:]
        slash = rest.find("/")
        if slash <= 0:
            return None
        addon = rest[:slash]
        path = rest[slash + 1 :]
        if path.startswith("../lib/"):
            url = f"/{addon}/static/lib/{path[len('../lib/') :]}"
        elif path.startswith("../tests/"):
            url = f"/{addon}/static/tests/{path[len('../tests/') :]}"
        else:
            url = f"/{addon}/static/src/{path}"
        if not url.endswith(".js"):
            url += ".js"
        return url

    @tools.conditional(
        "xml" not in tools.config["dev_mode"],
        tools.ormcache(
            "bundle",
            "tuple(sorted(assets_params.items()))",
            cache="assets",
        ),
    )
    def _get_native_module_data_cached(
        self,
        bundle: str,
        assets_params: dict[str, Any] | None = None,
    ) -> dict:
        """Fetch native module data for a bundle (cached in non-dev mode).

        Returns the dict from ``AssetsBundle.get_native_module_data()``,
        with sets converted to sorted tuples for cache serialization.
        """
        asset_bundle = self._get_asset_bundle(
            bundle,
            js=True,
            css=False,
            debug_assets=False,
            assets_params=assets_params,
        )
        return asset_bundle.get_native_module_data()

    def _get_esm_bundle_payload(
        self,
        bundle: str,
        assets_params: dict[str, Any] | None = None,
        debug_assets: bool = False,
    ) -> dict:
        """Payload for the ``/web/bundle`` lazy-load endpoint (dispatch).

        ``?debug=assets`` requests bypass the cache so file edits show up
        immediately, mirroring the native-module-nodes dispatch. Cached
        values are shared by reference — callers must treat the dict and
        its members as immutable.
        """
        if assets_params is None:
            assets_params = self.env["ir.asset"]._get_asset_params()
        if debug_assets:
            return self._esm_bundle_payload_impl(bundle, assets_params)
        return self._get_esm_bundle_payload_cached(bundle, assets_params)

    @tools.conditional(
        "xml" not in tools.config["dev_mode"],
        tools.ormcache(
            "bundle",
            "tuple(sorted(assets_params.items()))",
            cache="assets",
        ),
    )
    def _get_esm_bundle_payload_cached(
        self,
        bundle: str,
        assets_params: dict[str, Any] | None = None,
    ) -> dict:
        """Cached variant of the lazy-bundle payload (see the dispatch)."""
        return self._esm_bundle_payload_impl(bundle, assets_params)

    def _esm_bundle_payload_impl(
        self,
        bundle: str,
        assets_params: dict[str, Any] | None,
    ) -> dict:
        """Compute the lazy ESM bundle payload.

        Previously inlined in the ``/web/bundle`` controller and recomputed
        per request: bundle construction, bridge discovery (regex over every
        module source) and the XML template parse ran on every runtime
        ``loadBundle()`` call. The template attachment is content-addressed,
        so repeat computes reuse the same URL; the newest row per name
        survives ``_gc_esm_assets``, keeping cached payload URLs valid.
        """
        asset_bundle = self._get_asset_bundle(
            bundle,
            js=True,
            css=False,
            debug_assets=True,
            assets_params=assets_params,
        )
        native_data = asset_bundle.get_native_module_data()
        import_map = dict(native_data["import_map"])
        import_map.update(native_data.get("bridge_import_map", {}))
        template_url = None
        esm_tpl = asset_bundle.generate_esm_template_bundle(use_import=False)
        if esm_tpl:
            template_url = self._save_esm_attachment(f"{bundle}.templates", esm_tpl)
        return {
            "specifiers": sorted(native_data["import_map"]),
            "import_map": import_map,
            "template_url": template_url,
        }

    # Cache for the minified loader shim. Populated lazily by
    # _build_loader_shim_js() from the static source file on disk, and
    # only recomputed if the file's mtime changes (dev-mode hot reload).
    _loader_shim_cache: tuple[float, str] | None = None

    # ─────────────────────────────────────────────────────────────────
    # esbuild circuit breaker (per-process, per-bundle)
    # ─────────────────────────────────────────────────────────────────
    #
    # Each failure of ``esbuild_native_bundle()`` opens a cooldown window
    # during which we skip esbuild and serve the debug-mode fallback.
    # Protects against retry-storms when esbuild is broken (missing binary,
    # syntax error in source, permissions problem) — without a breaker,
    # every request would pay the subprocess startup + failure cost.
    #
    # State survives per worker process and is cleared on restart.  The
    # admin override below (``web.esbuild.force_fallback_bundles``
    # system parameter) provides the same effect without waiting for a
    # failure, e.g. to force debug-mode for a bundle after an incident.
    # Keyed by ``(db_name, bundle)`` via ``_esbuild_cooldown_key``. This is a
    # single process-global class attribute shared by every registry in the
    # worker (plain class attributes are inherited, not copied per registry —
    # see orm/registration.py), so it MUST be namespaced by database; otherwise
    # an esbuild failure for a bundle in one tenant opens the breaker for the
    # same bundle name in every other tenant.
    _esbuild_cooldowns: dict[tuple[str, str], tuple[float, str, int]] = {}
    # Hardcoded defaults — overridable via ir.config_parameter without a
    # code change.  Names mirror the parameter keys (see
    # ``_get_esbuild_setting``).  Keep the class attributes so existing
    # tests that read them directly (``self.IrQweb._ESBUILD_COOLDOWN_S``)
    # continue to pass with default semantics.
    _ESBUILD_COOLDOWN_S: float = 60.0  # after 1st failure
    _ESBUILD_EXTENDED_COOLDOWN_S: float = 600.0  # after 2nd consecutive failure

    # ─────────────────────────────────────────────────────────────────
    # Tunable settings (ir.config_parameter)
    # ─────────────────────────────────────────────────────────────────
    #
    # Surface every hardcoded esbuild timing as a system parameter so
    # ops can tune post-incident without redeploying.  Parameter keys
    # follow the ``web.esbuild.<name>`` convention for consistency with
    # the existing ``web.esbuild.force_fallback_bundles`` admin toggle.
    #
    # Defaults match the hardcoded values so existing behavior is
    # unchanged when no parameter is set.
    _ESBUILD_SETTING_KEYS: frozenset = frozenset(
        {
            "cooldown_s",
            "extended_cooldown_s",
            "lock_retries",
            "lock_retry_sleep_s",
            "timeout_s",
            "target",
            # Source-map mode: ``""`` (off — default), ``"linked"``
            # (RECOMMENDED for production debugging: sidecar ``.js.map``
            # attachment + a ``//# sourceMappingURL=`` directive in the
            # bundle — the only mode devtools and the error-dialog stack
            # annotator (``@web/core/errors/stack_frames``) can discover),
            # ``"external"`` (sidecar without the directive — for maps
            # consumed out-of-band, e.g. a crash reporter), or ``"inline"``
            # (base64 in the bundle, no sidecar but ~2x download).
            # Operators turn this on without redeploying; the ``.map``
            # sidecar is served immutable by ``content_esm_assets``.
            "source_maps",
        }
    )

    def _get_esbuild_setting(self, name: str, default, cast=None):
        """Return the value of ``web.esbuild.<name>``, falling back to
        ``default`` if unset / unparseable.

        Reads through ``ir.config_parameter`` (itself cached on the
        ``ormcache`` layer, so repeated lookups in the same transaction
        are cheap).  ``cast`` is applied to a non-None raw value; on
        cast failure the default is used and a DEBUG log records why so
        operators can spot a typo in their parameter.
        """
        if name not in self._ESBUILD_SETTING_KEYS:
            raise ValueError(
                f"Unknown esbuild setting {name!r}; "
                f"expected one of {sorted(self._ESBUILD_SETTING_KEYS)}",
            )
        raw = (
            self.env["ir.config_parameter"]
            .sudo()
            .get_param(
                f"web.esbuild.{name}",
            )
        )
        # get_param() returns ``False`` (not ``None``) when the key is
        # unset — a naive ``raw is None`` check would miss the common
        # case and poison callers with ``float(False) == 0.0``.  Use
        # Python truthiness: any legitimate string value is truthy
        # (``"0.0"`` is truthy even though its cast is 0.0).
        if not raw:
            return default
        if cast is None:
            return raw
        try:
            return cast(raw)
        except (TypeError, ValueError) as exc:
            log_event(
                _fallback_log,
                logging.DEBUG,
                "setting_cast_failed",
                name=name,
                raw=str(raw)[:50],
                err=type(exc).__name__,
            )
            return default

    def _esbuild_forced_fallback_bundles(self) -> set[str]:
        """Bundle names an admin has forced to the debug-mode fallback.

        Read from ``web.esbuild.force_fallback_bundles`` (comma-separated,
        ir.config_parameter — its ``get_param`` is itself ormcached). Consulted
        both by the production esbuild path and by ``_get_native_module_nodes``,
        which bypasses the node cache for these so a freshly added override
        silences a bundle without a server restart or cache clear.
        """
        forced_raw = (
            self.env["ir.config_parameter"]
            .sudo()
            .get_param("web.esbuild.force_fallback_bundles", "")
        )
        return {s.strip() for s in forced_raw.split(",") if s.strip()}

    def _esbuild_cooldown_key(self, bundle: str) -> tuple[str, str]:
        """Database-scoped key for ``_esbuild_cooldowns``.

        The cooldown dict is a single process-global class attribute shared by
        every registry in the worker, so an unscoped (bundle-only) key would let
        an esbuild failure in one database open the breaker for the same bundle
        name in every other database. Namespacing by ``cr.dbname`` isolates
        tenants while keeping the shared-dict design.
        """
        return (self.env.cr.dbname, bundle)

    def _esbuild_circuit_state(self, bundle: str) -> tuple[bool, str]:
        """Check the circuit-breaker state for a bundle.

        Returns ``(allow, reason)``.  When ``allow`` is False, callers
        should skip esbuild and go straight to the debug-mode fallback.
        """
        key = self._esbuild_cooldown_key(bundle)
        entry = type(self)._esbuild_cooldowns.get(key)
        if not entry:
            return True, ""
        expiry, reason, _fails = entry
        if time.monotonic() < expiry:
            return False, reason
        # Cooldown expired — clear the block so we try again.  Keep the
        # failure count so a second consecutive failure escalates to the
        # extended cooldown.
        type(self)._esbuild_cooldowns[key] = (0.0, reason, _fails)
        return True, ""

    def _esbuild_circuit_record_failure(self, bundle: str, reason: str) -> None:
        """Open the circuit for ``bundle`` after a failed build.

        Second consecutive failure promotes the cooldown to the extended
        value; a successful build clears the counter.  Cooldown values
        come from ``web.esbuild.cooldown_s`` / ``extended_cooldown_s``,
        falling back to the class-level defaults if unset.
        """
        key = self._esbuild_cooldown_key(bundle)
        prev = type(self)._esbuild_cooldowns.get(key)
        fails = (prev[2] + 1) if prev else 1
        if fails >= 2:
            cooldown = self._get_esbuild_setting(
                "extended_cooldown_s",
                default=self._ESBUILD_EXTENDED_COOLDOWN_S,
                cast=float,
            )
        else:
            cooldown = self._get_esbuild_setting(
                "cooldown_s",
                default=self._ESBUILD_COOLDOWN_S,
                cast=float,
            )
        type(self)._esbuild_cooldowns[key] = (
            time.monotonic() + cooldown,
            reason,
            fails,
        )
        log_event(
            _fallback_log,
            logging.WARNING,
            "circuit_open",
            bundle=bundle,
            reason=reason,
            cooldown_s=cooldown,
            fails=fails,
        )

    def _esbuild_circuit_record_success(self, bundle: str) -> None:
        """Close the circuit for ``bundle`` after a successful build."""
        cooldowns = type(self)._esbuild_cooldowns
        key = self._esbuild_cooldown_key(bundle)
        if key in cooldowns:
            cooldowns.pop(key, None)
            log_event(
                _fallback_log,
                logging.INFO,
                "circuit_close",
                bundle=bundle,
            )

    # ─────────────────────────────────────────────────────────────────
    # esbuild concurrency lock (advisory, transaction-scoped)
    # ─────────────────────────────────────────────────────────────────
    #
    # Rationale: two requests cold-starting the same bundle would each
    # spawn esbuild (3s on ``web.assets_web``) and both would try to
    # ``INSERT`` the same attachment, with only one winning.  The
    # duplicate-CPU path is visible as back-to-back ``event=bundled``
    # lines in the log.  A Postgres transaction-scoped advisory lock
    # serializes the expensive path: the first request acquires the
    # lock and runs esbuild; concurrent requests see the lock held,
    # degrade to the debug-mode branch for that single render (the
    # user's page loads, just with un-minified nodes), and the lock
    # auto-releases when the first request's transaction commits.
    #
    # We intentionally use ``pg_try_advisory_xact_lock`` (non-blocking)
    # with one short retry rather than a blocking acquire so we don't
    # tie up web workers behind a slow esbuild on a deployment where
    # reverse-proxy timeouts are shorter than esbuild startup.

    _ESBUILD_LOCK_RETRIES: int = 1
    _ESBUILD_LOCK_RETRY_SLEEP_S: float = 0.2

    def _esbuild_try_acquire_lock(self, bundle: str) -> bool:
        """Try to take the per-bundle advisory lock.

        Returns True if acquired; the lock is transaction-scoped and
        releases automatically when the current cursor's transaction
        commits or rolls back (no manual release needed).

        Returns False after ``retries + 1`` attempts, in which case the
        caller should fall back to the debug-mode path.  ``retries`` and
        the inter-attempt sleep are read from
        ``web.esbuild.lock_retries`` / ``lock_retry_sleep_s`` (defaults
        come from ``_ESBUILD_LOCK_RETRIES`` / ``_ESBUILD_LOCK_RETRY_SLEEP_S``).
        """
        retries = self._get_esbuild_setting(
            "lock_retries",
            default=self._ESBUILD_LOCK_RETRIES,
            cast=int,
        )
        sleep_s = self._get_esbuild_setting(
            "lock_retry_sleep_s",
            default=self._ESBUILD_LOCK_RETRY_SLEEP_S,
            cast=float,
        )
        key = f"esbuild:{bundle}"
        for attempt in range(retries + 1):
            self.env.cr.execute(
                "SELECT pg_try_advisory_xact_lock(hashtext(%s))",
                (key,),
            )
            got = self.env.cr.fetchone()[0]
            if got:
                log_event(
                    _lock_log,
                    logging.DEBUG,
                    "acquired",
                    bundle=bundle,
                    attempt=attempt,
                )
                return True
            if attempt < retries:
                time.sleep(sleep_s)
        log_event(
            _lock_log,
            logging.INFO,
            "contention",
            bundle=bundle,
            attempts=retries + 1,
        )
        return False

    @staticmethod
    def _is_hoot_test_specifier(specifier: str) -> bool:
        """Whether ``specifier`` resolves to a Hoot test file.

        Hoot wraps each test file inside a ``describe()`` suite, so eager
        import would bypass that wrapper.  Hoot tests are loaded through
        ``start.hoot``'s ``loadAndStart()`` instead.  Tour files
        (``/static/tests/tours/*.js``) and their specifiers
        (``@addon/../tests/tours/...``) are NOT Hoot tests — they
        register themselves into the ``web_tour.tours`` registry on
        module load and must be eagerly imported.
        """
        if "/tours/" in specifier:
            return False
        return (
            "/../tests/" in specifier or ".test" in specifier or "/tests/" in specifier
        )

    @classmethod
    def _build_loader_shim_js(cls) -> str:
        """Return a self-executing JS snippet that bootstraps ``odoo.loader``.

        The source lives in ``addons/web/static/src/module_loader.js`` so
        that it can be edited with regular JS tooling (linters, unit tests,
        syntax highlighting).  This method reads and minifies it once,
        caching the result keyed by the file's mtime so that local edits
        during development are picked up automatically.

        The loader MUST be a class instance (not a plain object) because
        Hoot-based tests subclass it via
        ``Object.getPrototypeOf(odoo.loader.constructor)`` and instantiate
        the subclass for isolated module graphs.  A plain-object shim
        would make the subclass extend ``Object`` and break that pattern.
        """
        src_path = Path(file_path("web/static/src/module_loader.js"))
        mtime = src_path.stat().st_mtime
        cached = cls._loader_shim_cache
        if cached and cached[0] == mtime:
            return cached[1]
        source = src_path.read_text(encoding="utf-8")
        # rjsmin preserves class syntax and IIFEs correctly.
        minified = _rjsmin(source)
        cls._loader_shim_cache = (mtime, minified)
        log_event(
            _loader_log,
            logging.DEBUG,
            "shim_compiled",
            source_bytes=len(source),
            minified_bytes=len(minified),
        )
        return minified

    @tools.conditional(
        # Mirror the links/native-data caches: cache "forever" in non-xml-debug
        # mode, cleared by ir.asset writes (clear_cache("assets")) and module
        # update, or a manual server-cache clear.
        "xml" not in tools.config["dev_mode"],
        tools.ormcache(
            "bundle",
            "tuple(sorted(assets_params.items()))",
            cache="assets",
        ),
    )
    def _get_native_module_nodes_cached(
        self,
        bundle: str,
        assets_params: dict[str, Any] | None = None,
    ) -> tuple[
        list[tuple[str, dict[str, Any]]],
        list[tuple[str, dict[str, Any]]],
    ]:
        """Cached production native-ESM nodes (non-debug, read-write only).

        Runs the full assembly via ``_get_native_module_nodes_impl`` and caches
        the resulting nodes, so warm renders skip bundle construction, the
        esbuild subprocess, and the template parse entirely. A production
        attempt that declines (esbuild circuit open, lock contention, or build
        failure) raises ``_EsmFallbackError`` instead of returning the degraded
        debug rendering — ormcache never stores an exception, so the fallback
        is never cached.
        """
        return self._get_native_module_nodes_impl(
            bundle,
            debug=False,
            assets_params=assets_params,
            _raise_on_decline=True,
        )

    def _get_native_module_nodes(
        self,
        bundle: str,
        debug: str | bool = False,
        assets_params: dict[str, Any] | None = None,
    ) -> tuple[
        list[tuple[str, dict[str, Any]]],
        list[tuple[str, dict[str, Any]]],
    ]:
        """Dispatch native-ESM node generation through the assets cache.

        Production (non-debug, read-write) renders go through the ormcached
        ``_get_native_module_nodes_cached``. ``?debug=assets``, read-only
        cursors (which inline the bundle rather than persist an attachment),
        and the esbuild-declined fallback all render uncached via
        ``_get_native_module_nodes_impl``.
        """
        debug_assets = debug and "assets" in debug
        if assets_params is None:
            assets_params = self.env["ir.asset"]._get_asset_params()
        if (
            not debug_assets
            and not self.env.cr.readonly
            and bundle not in self._esbuild_forced_fallback_bundles()
        ):
            try:
                pre, post = self._get_native_module_nodes_cached(
                    bundle, assets_params=assets_params
                )
            except _EsmFallbackError:
                # Production esbuild declined (circuit open, admin override,
                # lock contention, or build failure) → render the uncached
                # debug fallback. The re-run re-evaluates those conditions
                # (cheap; no second subprocess once the circuit has opened) and
                # constructs the asset_bundle the debug branch needs.
                pre, post = self._get_native_module_nodes_impl(
                    bundle, debug=debug, assets_params=assets_params
                )
        else:
            pre, post = self._get_native_module_nodes_impl(
                bundle, debug=debug, assets_params=assets_params
            )
        return self._dedup_request_import_map(bundle, pre), post

    def _dedup_request_import_map(
        self,
        bundle: str,
        pre_nodes: list[tuple[str, dict[str, Any]]],
    ) -> list[tuple[str, dict[str, Any]]]:
        """Keep at most one ``<script type="importmap">`` per request.

        The browser evaluates every importmap on the page and logs "An
        import map rule for specifier '<spec>' was removed, as it
        conflicted with an existing rule" for each duplicate key, so a
        page composing several ESM bundles (``t-call-assets`` twice, the
        unit-test page stacking setup + tests bundles) must render the
        map of the FIRST bundle only.

        Runs in the dispatcher — outside ``_get_native_module_nodes_cached``
        — because the decision is request-scoped while the cache key is
        ``(bundle, assets_params)``: filtering inside the cached impl baked
        one request's page composition into every later render (nodes
        cached without their importmap serve broken pages forever).

        Returns a filtered COPY when dropping the node; cached lists are
        shared by reference and must never be mutated.
        """
        if not request:
            return pre_nodes

        def _is_import_map(node: tuple[str, dict[str, Any]]) -> bool:
            return node[0] == "script" and node[1].get("type") == "importmap"

        if not any(_is_import_map(node) for node in pre_nodes):
            return pre_nodes
        if not getattr(request, "_esm_import_map_rendered", False):
            request._esm_import_map_rendered = True
            return pre_nodes
        log_event(
            _esm_log,
            logging.DEBUG,
            "importmap_skipped",
            bundle=bundle,
            reason="already_rendered",
        )
        return [node for node in pre_nodes if not _is_import_map(node)]

    def _get_native_module_nodes_impl(
        self,
        bundle: str,
        debug: str | bool = False,
        assets_params: dict[str, Any] | None = None,
        _raise_on_decline: bool = False,
    ) -> tuple[
        list[tuple[str, dict[str, Any]]],
        list[tuple[str, dict[str, Any]]],
    ]:
        """Generate import map, OWL pre-load, and bridge nodes for native ESM.

        :param str bundle: name of the asset bundle to render
        :param debug: debug flags (``'assets'`` rebuilds without cache)
        :param assets_params: parameters forwarded to ``ir.asset``
        :return: 2-tuple ``(pre_nodes, post_nodes)`` flanking the legacy bundle
        :rtype: tuple[list, list]
        """
        # ``pre_nodes`` go BEFORE the legacy bundle:
        #   1. ``<script src="owl.js">`` — non-deferred, sets ``window.owl``
        #   2. ``<script type="importmap">`` with specifier → URL mappings
        #   3. ``<link rel="modulepreload">`` hints (production only)
        # ``post_nodes`` go AFTER the legacy bundle:
        #   4. ``<script type="module">`` bridge — imports native modules
        #      and registers them in ``odoo.loader.modules`` via
        #      ``registerNativeModules()``.  Runs after the bundle because
        #      both ``defer`` and ``type="module"`` share the same deferred
        #      execution queue in document order.
        debug_assets = debug and "assets" in debug
        if assets_params is None:
            assets_params = self.env["ir.asset"]._get_asset_params()

        if debug_assets:
            # In debug mode, rebuild from scratch (no cache)
            asset_bundle = self._get_asset_bundle(
                bundle,
                js=True,
                css=False,
                debug_assets=True,
                assets_params=assets_params,
            )
            native_data = asset_bundle.get_native_module_data()
        else:
            native_data = self._get_native_module_data_cached(
                bundle,
                assets_params=assets_params,
            )

        if not native_data["import_map"]:
            log_event(
                _esm_log,
                logging.DEBUG,
                "no_native_modules",
                bundle=bundle,
            )
            return [], []

        # ── Production: esbuild bundling ──
        # Single minified <script type="module"> replaces 600+ individual
        # files + import map + modulepreload hints + bridge script.
        #
        # Two pre-checks short-circuit the expensive path (subprocess +
        # attachment insert) straight to the debug-mode fallback:
        #
        #   • Admin override via ``web.esbuild.force_fallback_bundles``
        #     (comma-separated bundle names in ir.config_parameter) —
        #     operators can silence a broken bundle without a restart.
        #   • Circuit breaker state — set by ``_esbuild_circuit_record_failure``
        #     on prior failures; blocks retries until the cooldown expires.
        #
        # Both cases fall through to the existing debug-mode branch,
        # which serves individual ES modules + import map.  Rendering is
        # slower and uglier (no minification, modulepreload hints still
        # emitted) but functional.
        if not debug_assets:
            asset_bundle = self._get_asset_bundle(
                bundle,
                js=True,
                css=False,
                debug_assets=False,
                assets_params=assets_params,
            )
            esbuild_result, child_bundles = self._esm_run_esbuild(
                bundle, asset_bundle, assets_params
            )
            if esbuild_result.code:
                return self._esm_prod_nodes(
                    bundle, asset_bundle, esbuild_result, assets_params, child_bundles
                )
            if _raise_on_decline:
                raise _EsmFallbackError
        return self._esm_debug_nodes(
            bundle, asset_bundle, native_data, debug_assets, assets_params
        )

    def _esm_run_esbuild(
        self,
        bundle: str,
        asset_bundle: AssetsBundle,
        assets_params: dict[str, Any] | None,
    ) -> tuple[EsbuildResult, list[AssetsBundle]]:
        """Run production esbuild bundling for ``bundle`` if allowed.

        Honors the admin force-fallback override, the per-bundle circuit
        breaker and the advisory build lock, and records circuit
        success/failure.

        :return: ``(esbuild_result, child_bundles)`` — the esbuild build
            (its ``.code`` is ``""`` when the build is skipped or fails;
            the caller then degrades to the debug-mode nodes, and
            ``.metafile`` / ``.sourcemap`` carry the sibling artifacts) and
            the dynamic-child ``AssetsBundle`` objects constructed for the
            spec scan, for ``_esm_prod_nodes`` to reuse instead of
            re-constructing all of them (empty when the build was skipped
            — the prod-nodes path is not reached in that case).
        """
        # Admin override (``web.esbuild.force_fallback_bundles``). The node
        # cache is bypassed for these in the dispatcher, so reaching here
        # for a forced bundle means an uncached (debug / fallback) render.
        forced_bundles = self._esbuild_forced_fallback_bundles()

        allow, circuit_reason = self._esbuild_circuit_state(bundle)
        esbuild_result = EsbuildResult("", None, None)
        child_bundles: list[AssetsBundle] = []
        if bundle in forced_bundles:
            log_event(
                _fallback_log,
                logging.INFO,
                "admin_override",
                bundle=bundle,
            )
        elif not allow:
            # Silent skip during cooldown — the circuit-open event
            # was logged once when the breaker tripped, so don't
            # spam the log with a line per request.
            log_event(
                _fallback_log,
                logging.DEBUG,
                "circuit_blocked",
                bundle=bundle,
                reason=circuit_reason,
            )
        elif not self._esbuild_try_acquire_lock(bundle):
            # Another request is mid-build; degrade THIS render to
            # debug-mode so the user's page loads without waiting.
            # Emitted at INFO because contention is interesting for
            # capacity planning (frequent misses → consider
            # pre-generation via ``_pregenerate_assets_bundles``).
            log_event(
                _fallback_log,
                logging.INFO,
                "lock_contention",
                bundle=bundle,
            )
        else:
            # Pre-compute dynamic children's native-module specs so
            # the parent's esbuild call can externalise them (see
            # the docstring on ``esbuild_native_bundle``).  Done
            # here because qweb already has access to ``_get_asset_bundle``
            # and the cost is paid by the import-map merge below
            # anyway — handing the same data to esbuild costs only
            # a set comprehension.
            _child_specs: set[str] = set()
            for _child_name in esm_registry().dynamic_children.get(bundle, ()):
                _child_ab = self._get_asset_bundle(
                    _child_name,
                    js=True,
                    css=False,
                    debug_assets=(_child_name in esm_registry().dynamic_bundle_names),
                    assets_params=assets_params,
                )
                child_bundles.append(_child_ab)
                _child_specs.update(a.module_path for a in _child_ab.native_modules)
            try:
                esbuild_result = asset_bundle.esbuild_native_bundle(
                    timeout_s=self._get_esbuild_setting(
                        "timeout_s",
                        default=EsbuildCompiler._ESBUILD_TIMEOUT_S,
                        cast=int,
                    ),
                    target=self._get_esbuild_setting(
                        "target",
                        default=EsbuildCompiler._ESBUILD_TARGET,
                    ),
                    source_maps=self._get_esbuild_setting(
                        "source_maps",
                        default=EsbuildCompiler._ESBUILD_SOURCE_MAPS,
                    ),
                    dynamic_child_specs=frozenset(_child_specs) or None,
                )
                self._esbuild_circuit_record_success(bundle)
            except Exception as e:
                # Distinct ``odoo.assets.fallback`` event so alerting
                # on prod→debug degradation doesn't require
                # string-matching on a free-form message.  The
                # degraded rendering is handled by falling through
                # into the debug-mode branch below.
                log_event(
                    _fallback_log,
                    logging.WARNING,
                    "esbuild_exception",
                    bundle=bundle,
                    err=type(e).__name__,
                    msg=str(e)[:200],
                )
                self._esbuild_circuit_record_failure(
                    bundle,
                    reason=type(e).__name__,
                )
                esbuild_result = EsbuildResult("", None, None)
        return esbuild_result, child_bundles

    def _esm_prod_nodes(
        self,
        bundle: str,
        asset_bundle: AssetsBundle,
        esbuild_result: EsbuildResult,
        assets_params: dict[str, Any] | None,
        child_bundles: list[AssetsBundle] | None = None,
    ) -> tuple[
        list[tuple[str, dict[str, Any]]],
        list[tuple[str, dict[str, Any]]],
    ]:
        """Assemble production native-ESM nodes from a successful esbuild build.

        Builds the merged import map (externals, dynamic bundles, includes,
        secondary satellites, self-bridges and alias overrides), emits the
        importmap + loader shim, inlines template registration into the
        bundle, and persists (or inlines, in read-only txns) the module and
        templates attachments.

        :param EsbuildResult esbuild_result: the successful build — its
            ``.code`` is the bundle source; ``.metafile`` / ``.sourcemap``
            are persisted as sibling attachments alongside the module.
        :param list child_bundles: dynamic-child ``AssetsBundle`` objects
            already constructed by ``_esm_run_esbuild`` (same construction
            parameters as the fallback below); ``None`` constructs them.
        :return: ``(pre, post)`` flanking the legacy bundle
        """
        esbuild_code = esbuild_result.code
        pre = []
        post = []
        # Import map: @odoo/* externals + dynamic bundle specifiers
        # so runtime import() can resolve them.
        prod_import_map = dict(self._ODOO_EXTERNAL_LIBS)

        # Collect dynamic ESM bundles and build bridges for
        # their @web/... dependencies (data: URI shims reading
        # from odoo.loader.modules — same instance, no dups).
        # The child bundles were already constructed once by
        # ``_esm_run_esbuild`` for the spec scan; reuse them here
        # instead of re-running every child's ``__init__`` (15
        # constructions saved per cold ``web.assets_web`` render).
        if child_bundles is None:
            child_bundles = [
                self._get_asset_bundle(
                    lazy_name,
                    js=True,
                    css=False,
                    debug_assets=lazy_name in esm_registry().dynamic_bundle_names,
                    assets_params=assets_params,
                )
                for lazy_name in esm_registry().dynamic_children.get(bundle, ())
            ]
        dynamic_bundles = []
        for lazy_ab in child_bundles:
            is_dynamic = lazy_ab.name in esm_registry().dynamic_bundle_names
            # Only ``import_map`` is consumed here — the combined
            # dynamic-child bridge is built separately below — so skip
            # the per-child bridge build + attachment persistence.
            lazy_data = lazy_ab.get_native_module_data(with_bridges=False)
            prod_import_map.update(lazy_data["import_map"])
            if is_dynamic:
                dynamic_bundles.append(lazy_ab)

        # Build instance-sharing bridges for dynamic bundles.
        # Combine ALL dynamic bundles' native_modules so that
        # bridges export the union of all needed names (e.g.
        # spreadsheet needs `groupBy` from arrays, website
        # needs `shallowEqual` — both must be in one bridge).
        if dynamic_bundles:
            combined_modules = []
            for dyn_ab in dynamic_bundles:
                combined_modules.extend(dyn_ab.native_modules)
            # The first bundle hosts the build (persistence env + log
            # name); the combined module list is passed explicitly.
            bridge_map = dynamic_bundles[0]._bridges._build_native_to_legacy_bridge(
                set(prod_import_map),
                modules=combined_modules,
            )
            prod_import_map.update(bridge_map)

        # Include import map entries from associated bundles
        # (e.g. test bundles that skip esbuild and rely on the
        # parent's import map for bare-specifier resolution).
        include_names = esm_registry().import_map_includes.get(bundle, ())
        for include_name in include_names:
            # debug_assets=False here → reuse the ormcached native
            # module data (keyed by bundle + assets_params) instead of
            # rebuilding the bundle and its bridge on every render.
            include_data = self._get_native_module_data_cached(
                include_name,
                assets_params=assets_params,
            )
            prod_import_map.update(include_data["import_map"])
            # The include's bridges cover specifiers its OWN files import
            # from elsewhere — mostly this parent's modules (absent from
            # the map, added here) but also DYNAMIC-CHILD specifiers,
            # which already have a direct URL from the child merge above.
            # Those must keep the direct URL: the parent's esbuild output
            # externalizes dynamic-child specs and imports them through
            # the map at page-load time, when ``odoo.loader.modules`` is
            # not yet populated — a shim there yields undefined exports.
            # The direct URL also preserves singleton identity for the
            # satellite (browsers singleton ES modules by URL).  Same
            # first-wins rule the secondary-includes loop below applies.
            for spec, shim_url in include_data.get("bridge_import_map", {}).items():
                prod_import_map.setdefault(spec, shim_url)

        # Include NEW import-map specifiers from secondary
        # satellite bundles (e.g. ``web.assets_tests`` loaded
        # via the conditional template).  Only specifiers not
        # already in the parent are added so we don't override
        # the parent's resolved URLs with the satellite's
        # bridge shims (which would create circular shim
        # references during the parent's bridge initialisation).
        secondary_names = esm_registry().secondary_import_map_includes.get(
            bundle,
            [],
        )
        for sec_name in secondary_names:
            sec_ab = self._get_asset_bundle(
                sec_name,
                js=True,
                css=False,
                debug_assets=False,
                assets_params=assets_params,
            )
            # Only ``import_map`` is consumed; skip the bridge build.
            sec_data = sec_ab.get_native_module_data(with_bridges=False)
            for spec, url in sec_data["import_map"].items():
                prod_import_map.setdefault(spec, url)

        # When satellites exist, they load individual source
        # files from this bundle.  Those files may import bare
        # specifiers (``@ai/vad_audio_recorder``) that are only
        # resolved internally inside the esbuild bundle — the
        # browser sees the raw source and needs an import-map
        # entry.  Emit self-bridges that read from
        # ``odoo.loader.modules`` (populated by the esbuild
        # bundle's ``registerNativeModules`` call).
        #
        # IMPORTANT: bridges OVERRIDE any URL mapping a satellite
        # may have published for the same specifier.  Reason:
        # cross-bundle module sharing requires the satellite's
        # ``import { GraphModel } from "@web/views/graph/graph_model"``
        # to land on the parent's already-registered singleton
        # (loaded inline inside the esbuild bundle), NOT to fetch
        # ``/web/static/src/views/graph/graph_model.js`` and
        # re-evaluate it as a second module instance.  Satellites
        # legitimately expose URLs for their OWN test files; for
        # production files transitively included by satellite-
        # contributed sub-bundles (e.g. ``spreadsheet/__manifest__``
        # adds ``web/static/src/views/graph/graph_model.js`` to
        # ``spreadsheet.o_spreadsheet``, which is then included
        # into ``web.assets_unit_tests`` via the test-bundle
        # contribution) those URLs would otherwise cause every
        # ``patchWithCleanup(GraphModel.prototype, …)`` in a test
        # to patch a parallel-universe class that the production
        # controller never sees.  The bridge resolution preserves
        # singleton identity, which is also what HOOT's mocks
        # ``patchWithCleanup`` rely on.
        if include_names:
            self_bridges = asset_bundle._bridges._build_parent_self_bridge()
            prod_import_map.update(self_bridges)
            # ── Alias override ──────────────────────────────
            # Modules that declare an ``alias=@odoo/xyz``
            # header (hoot.js / hoot-dom.js / hoot-mock.js)
            # are present in ``_ODOO_EXTERNAL_LIBS`` with a
            # DIRECT URL pointing at the vendored ESM file.
            # That direct URL causes satellites' bare imports
            # (``import "@odoo/hoot"``) to fetch the file and
            # RE-EVALUATE it — the same file that the esbuild
            # bundle already inlined, duplicating side-effects
            # like ``customElements.define("hoot-fixture", …)``
            # in ``fixture.js``.  Reuse the self-bridge for
            # the asset's native module_path and key it under
            # the alias too, so the satellite reads from
            # ``odoo.loader.modules`` instead of re-fetching.
            from odoo.tools.assets.esm_graph import (
                _parse_odoo_module_header as _parse_hdr,
            )

            for asset in asset_bundle.native_modules:
                header = _parse_hdr(asset.raw_content)
                if not (header and header["alias"]):
                    continue
                alias = header["alias"]
                current = prod_import_map.get(alias, "")
                # ``/web/assets/esm/bridges/`` is the bridge
                # attachment prefix (see
                # ``BridgeShimManager._persist_bridge_shims``).  When
                # the alias already resolves to a bridge URL,
                # leave it alone — the existing shim reads from
                # the same ``odoo.loader.modules`` entry we'd
                # overwrite it with, so clobbering only churns
                # the attachment URL without changing semantics.
                if current.startswith("/web/assets/esm/bridges/"):
                    continue
                shim = self_bridges.get(asset.module_path)
                if shim:
                    prod_import_map[alias] = shim

        # ALWAYS emit the importmap node here.  Only ONE
        # ``<script type="importmap">`` may be evaluated per
        # document, but this method runs inside the ormcached
        # ``_get_native_module_nodes_cached`` whose key is
        # ``(bundle, assets_params)`` — request-independent.
        # Consulting ``request._esm_import_map_rendered`` here
        # (as this method used to) baked one request's page
        # composition into the process cache: a bundle first
        # rendered as the SECOND ESM bundle of a page was cached
        # WITHOUT its importmap and served broken to every later
        # page that rendered it alone.  The per-request dedup now
        # happens outside the cache, in the dispatcher
        # (``_get_native_module_nodes`` →
        # ``_dedup_request_import_map``); the debug branch keeps
        # its own flag handling because it is never cached and
        # the flag also shapes its generated bridge code.
        pre.append(
            (
                "script",
                {
                    "type": "importmap",
                    "data-bundle": bundle,
                    "text": json_mod.dumps(
                        {"imports": prod_import_map},
                    ),
                },
            )
        )
        # Bootstrap odoo.loader — must be a class instance (not
        # a plain object) because Hoot's ModuleSetLoader does
        # ``extends loader.constructor`` and calls parent methods
        # like startModule/addJob via the prototype chain.
        shim_js = self._build_loader_shim_js()
        pre.append(("script", {"text": shim_js}))
        # Inline the templates-registration code at the END of
        # the bundle's module body so ``registerTemplate(...)``
        # calls run SYNCHRONOUSLY right after
        # ``registerNativeModules({...})`` — and crucially
        # *before* the microtask queue drains.
        #
        # Why this matters: the bundle's source files often do
        # ``whenReady(() => mount(MyComponent, ...))`` at module
        # top level.  ``whenReady`` resolves immediately when
        # the document is already parsed (which it is by the
        # time deferred module scripts execute), so the mount
        # callback is queued as a microtask during this
        # bundle's evaluation.  If templates were emitted as a
        # SEPARATE ``<script type="module">`` after this one,
        # the browser would drain microtasks BETWEEN the two
        # modules — the mount would run with no templates
        # registered, throwing "Missing template: <name>".
        # Inlining keeps both into one module body so the
        # microtask drain (and therefore any whenReady mount)
        # happens AFTER both registerNativeModules and
        # registerTemplate have run.
        #
        # ``use_import=False`` makes the templates code reach
        # for ``odoo.loader.modules.get("@web/core/templates")``
        # rather than ``import``, so it picks up the SAME
        # module instance just registered above (no double-
        # evaluation, singleton identity preserved).
        esm_tpl = asset_bundle.generate_esm_template_bundle(
            use_import=False,
        )
        bundle_code = esbuild_code
        if esm_tpl:
            # When source maps are on, esbuild emits a
            # ``//# sourceMappingURL=<name>.map`` directive at
            # the END of its output so devtools knows where to
            # fetch the map from.  Browsers read the LAST
            # sourceMappingURL comment in the file — if we
            # append the templates body after the directive,
            # the directive becomes invisible to devtools and
            # source maps silently stop working.  Strip it
            # before appending templates, then re-emit it at
            # the very end so the combined bundle still has a
            # trailing directive.
            esb_base = esbuild_code
            sm_directive = ""
            _tail_idx = esbuild_code.rfind("//# sourceMappingURL=")
            if _tail_idx != -1 and "\n" not in esbuild_code[_tail_idx:].rstrip("\n"):
                # Match spans from the directive marker to the
                # end of file (possibly followed by a single
                # trailing newline).  esbuild always emits the
                # directive as the LAST non-empty line.
                sm_directive = esbuild_code[_tail_idx:].rstrip("\n")
                esb_base = esbuild_code[:_tail_idx].rstrip("\n") + "\n"
            bundle_code = (
                esb_base
                + "/* ── Inlined templates registration ── */\n"
                + esm_tpl
                + ("\n" + sm_directive + "\n" if sm_directive else "")
            )
        # Persist and reference by URL even on read-only request cursors:
        # ``_save_esm_attachment`` routes its INSERT through a dedicated
        # read-write registry cursor (a primary cursor even on a
        # replica-routed render — see ``_persist_esm_attachment_rows``),
        # so replica renders no longer inline the multi-MB bundle into
        # every response.  Inlining remains as the degradation path for
        # contexts with no writable cursor at all (read-only test
        # cursors, primary down) — functionally identical, just heavier.
        esm_url = None
        try:
            esm_url = self._save_esm_attachment(
                bundle,
                bundle_code,
                metafile=esbuild_result.metafile,
                sourcemap=esbuild_result.sourcemap,
            )
        except ReadOnlySqlTransaction:
            # Raised cleanly (no SQL executed) by
            # ``_persist_esm_attachment_rows`` when no writable cursor
            # exists — the transaction is intact, inlining is safe.
            # Anything else propagates as before: a real save error must
            # not be papered over with a silently degraded page.
            log_event(
                _attach_log,
                logging.WARNING,
                "save_failed_inline",
                bundle=bundle,
                readonly=bool(self.env.cr.readonly),
            )
        if esm_url:
            post.append(
                (
                    "script",
                    {
                        "type": "module",
                        "src": esm_url,
                        "data-bridge": bundle,
                    },
                )
            )
        else:
            post.append(
                (
                    "script",
                    {
                        "type": "module",
                        "text": bundle_code,
                        "data-bridge": bundle,
                    },
                )
            )
        # Companion templates attachment for IMPORT_MAP_INCLUDES
        # satellites: bundles in IMPORT_MAP_INCLUDES need the
        # templates as a separately-resolvable specifier in
        # their parent's import map (so test files that import
        # ``@web/core/templates`` resolve to the parent's
        # registered instance).  Skipped when the templates
        # are already inlined into the main bundle and no
        # satellite needs them.
        _has_satellites = bool(
            esm_registry().import_map_includes.get(bundle),
        )
        if esm_tpl and _has_satellites:
            # Same persist-or-inline ladder as the main bundle above.
            tpl_url = None
            try:
                tpl_url = self._save_esm_attachment(
                    f"{bundle}.templates",
                    esm_tpl,
                )
            except ReadOnlySqlTransaction:
                log_event(
                    _attach_log,
                    logging.WARNING,
                    "save_failed_inline",
                    bundle=f"{bundle}.templates",
                    readonly=bool(self.env.cr.readonly),
                )
            if tpl_url:
                post.append(
                    (
                        "script",
                        {
                            "type": "module",
                            "src": tpl_url,
                            "data-templates": bundle,
                        },
                    )
                )
            else:
                post.append(
                    (
                        "script",
                        {
                            "type": "module",
                            "text": esm_tpl,
                            "data-templates": bundle,
                        },
                    )
                )
        # URL-vs-data-URI breakdown helps correlate browser-side
        # "import map rule was removed" warnings with the exact
        # mix of specifier targets the server rendered.  A
        # client-side seed from this map should eliminate all
        # "conflicting rule" warnings for lazy bundles.
        # Bridge URIs used to be ``data:text/javascript,...``
        # (pre-refactor); now they're attachment URLs at
        # ``/web/assets/esm/bridges/<hash>.js``.  The
        # diagnostic still splits the two so historical log
        # comparisons make sense — any ``data:`` counts after
        # the refactor would indicate a caller hasn't migrated.
        _n_bridges = sum(
            1
            for v in prod_import_map.values()
            if v.startswith("/web/assets/esm/bridges/")
        )
        _n_data_uri = sum(1 for v in prod_import_map.values() if v.startswith("data:"))
        _n_real_url = len(prod_import_map) - _n_bridges - _n_data_uri
        log_event(
            _esm_log,
            logging.DEBUG,
            "render",
            bundle=bundle,
            branch="prod",
            pre=len(pre),
            post=len(post),
            importmap=len(prod_import_map),
            url=_n_real_url,
            bridges=_n_bridges,
            data=_n_data_uri,
            dyn=len(dynamic_bundles),
            includes=len(include_names) if include_names else 0,
        )
        return pre, post

    def _esm_debug_nodes(
        self,
        bundle: str,
        asset_bundle: AssetsBundle,
        native_data: dict[str, Any],
        debug_assets: bool,
        assets_params: dict[str, Any] | None,
    ) -> tuple[
        list[tuple[str, dict[str, Any]]],
        list[tuple[str, dict[str, Any]]],
    ]:
        """Build debug-mode (individual-file) native-ESM nodes.

        Emits the import map, the loader shim, the bridge module (eager imports
        + Hoot ``loadAndStart``) and the template module — all inline, no esbuild
        and no attachment writes. Bridge shims are resolved to direct URLs
        because debug mode has no esbuild bundle to populate
        ``odoo.loader.modules``. Reached for ``?debug=assets`` and as the
        uncached fallback when production esbuild declines.

        :return: ``(pre_nodes, post_nodes)`` flanking the legacy bundle
        """
        # ── Debug mode: individual files + import map ──
        pre_nodes = []
        post_nodes = []
        import_map = dict(native_data["import_map"])

        # Add @odoo/* externals to the import map so native modules
        # can resolve bare specifiers externalized by esbuild.
        import_map.update(self._ODOO_EXTERNAL_LIBS)

        # Pre-register dynamic ESM bundle specifiers in the import map
        # so that runtime import() (after loadBundle) can resolve them.
        # Only URLs are added — modules are NOT eagerly loaded.

        lazy_bundles = []
        for lazy_name in esm_registry().dynamic_children.get(bundle, ()):
            lazy_ab = self._get_asset_bundle(
                lazy_name,
                js=True,
                css=False,
                debug_assets=True,
                assets_params=assets_params,
            )
            # Only ``import_map`` is consumed (no bridge used here); skip the
            # discarded per-child bridge build.
            lazy_data = lazy_ab.get_native_module_data(with_bridges=False)
            import_map.update(lazy_data["import_map"])
            lazy_bundles.append(lazy_ab)

        # Include import map entries from associated bundles (e.g. test
        # bundles that skip esbuild and rely on the parent's import map).
        for include_name in esm_registry().import_map_includes.get(bundle, ()):
            include_ab = self._get_asset_bundle(
                include_name,
                js=True,
                css=False,
                debug_assets=debug_assets,
                assets_params=assets_params,
            )
            include_data = include_ab.get_native_module_data(with_bridges=False)
            import_map.update(include_data["import_map"])
            # The include's modules import cross-bundle specifiers the map
            # must resolve, but bridge SHIMS read ``odoo.loader.modules`` —
            # non-functional in debug mode (same reason as the conversion
            # loop below).  Merging them verbatim shadowed the parent's
            # direct URLs and poisoned the whole module graph: verified
            # 2026-06-10, the hoot runner failed all ~1311 tests under
            # ``?debug=assets`` (vs 8 genuine failures in production mode)
            # with every shim-routed export ``undefined``.  Discover the
            # specifier KEYS only — building and persisting the shim values
            # (~340 attachment writes per debug render) was pure waste once
            # every entry gets converted anyway — and resolve each to a
            # direct URL: keep an existing direct mapping, else derive the
            # static URL, else drop for a clean "module not found".  The
            # exclusion set is the include's own import-map keys, i.e. the
            # exact ``native_specifiers`` the bridge build would have used.
            discovered, _ext_seen = include_ab._bridges._discover_bridge_specifiers(
                set(include_data["import_map"]),
                set(self._ODOO_EXTERNAL_LIBS),
            )
            for _spec in discovered:
                _current = import_map.get(_spec)
                if _current and not _current.startswith(
                    ("/web/assets/esm/bridges/", "data:")
                ):
                    continue
                _resolved = self._ODOO_EXTERNAL_LIBS.get(
                    _spec
                ) or self._specifier_to_static_url(_spec)
                if _resolved:
                    import_map[_spec] = _resolved
                elif _current:
                    del import_map[_spec]

        # Include NEW import-map specifiers from secondary satellite
        # bundles (e.g. ``web.assets_tests`` loaded via the conditional
        # template).  Only specifiers not already in the parent are
        # added so we don't override the parent's resolved URLs with
        # the satellite's bridge shims.
        for sec_name in esm_registry().secondary_import_map_includes.get(bundle, ()):
            sec_ab = self._get_asset_bundle(
                sec_name,
                js=True,
                css=False,
                debug_assets=debug_assets,
                assets_params=assets_params,
            )
            # Only ``import_map`` is consumed; skip the bridge build.
            sec_data = sec_ab.get_native_module_data(with_bridges=False)
            for spec, url in sec_data["import_map"].items():
                import_map.setdefault(spec, url)

        # Instance-sharing bridge: data: URI shims that re-export from
        # ``odoo.loader.modules`` so dynamic bundles share the parent
        # bundle's singleton instances (e.g. same registry).
        # When dynamic bundles exist, rebuild the bridge with COMBINED
        # native modules (main + dynamic) so all needed exports are
        # included in a single shim per specifier.
        all_native_specifiers = set(native_data["import_map"])
        combined_native_modules = list(asset_bundle.native_modules)
        for lazy_ab in lazy_bundles:
            all_native_specifiers.update(m.module_path for m in lazy_ab.native_modules)
            combined_native_modules.extend(lazy_ab.native_modules)

        # In debug mode, bridge shims (modules reading from
        # odoo.loader.modules) CANNOT work: there is no esbuild
        # bundle to pre-populate the modules map, so _m is undefined
        # and the shim crashes.  Discover the specifier KEYS only —
        # building and persisting shim attachments here was pure waste
        # (same reasoning as the include-path conversion above) — and
        # resolve each to a direct URL:
        # 1. If the specifier already has a direct URL in import_map
        #    (from native_data or _ODOO_EXTERNAL_LIBS), keep it —
        #    the existing URL is already correct.
        # 2. Otherwise, resolve the @addon/... specifier back to a
        #    served static URL.  This is always safe in debug:
        #    browsers singleton ES modules by URL, so every bundle
        #    that imports the same specifier shares the exact same
        #    module instance.
        # 3. If the specifier can't be resolved (unusual), leave it
        #    out — the browser gets a clean "module not found"
        #    instead of the confusing undefined-property crash.
        discovered, _ext_seen = asset_bundle._bridges._discover_bridge_specifiers(
            all_native_specifiers,
            set(self._ODOO_EXTERNAL_LIBS),
            modules=combined_native_modules,
        )
        resolved_bridges = {}
        for _spec in discovered:
            _current = import_map.get(_spec)
            # A "direct URL" here means a real source/asset URL pointing
            # at a file NOT generated by ``_persist_bridge_shims``
            # (i.e. anything outside ``/web/assets/esm/bridges/``).  If
            # the spec already resolves to such a URL, a bridge is
            # redundant — the direct URL hits the source bytes, a
            # shim would only proxy through ``odoo.loader.modules``.
            if (
                _current
                and not _current.startswith("/web/assets/esm/bridges/")
                and not _current.startswith("data:")
            ):
                continue
            # No direct URL — prefer the canonical mapping in
            # _ODOO_EXTERNAL_LIBS (deep-import aliases like
            # @odoo/hoot-dom-helpers-events resolve to a vendored
            # path that the ``@addon/...`` → ``/addon/static/src/...``
            # convention can't compute), then fall back to the
            # convention-derived static URL.
            _resolved = self._ODOO_EXTERNAL_LIBS.get(
                _spec
            ) or self._specifier_to_static_url(_spec)
            if _resolved:
                resolved_bridges[_spec] = _resolved
        import_map.update(resolved_bridges)

        # Check if a previous ESM bundle on this page already rendered
        # an import map (e.g. the setup bundle on the test page).
        # Only ONE import map per document is allowed by the spec.
        _req = request or None
        _already_has_esm = _req and getattr(
            _req,
            "_esm_import_map_rendered",
            False,
        )

        # 1. Import map — MUST come before any <script type="module">
        if not _already_has_esm:
            pre_nodes.append(
                (
                    "script",
                    {
                        "type": "importmap",
                        "data-bundle": bundle,
                        "text": json_mod.dumps({"imports": import_map}, indent=2),
                    },
                )
            )
            if _req:
                _req._esm_import_map_rendered = True

        # 3. Modulepreload hints for faster loading (skip in debug mode
        #    to reduce noise and allow individual file debugging)
        if not debug_assets:
            pre_nodes.extend(
                ("link", {"rel": "modulepreload", "href": url})
                for url in native_data["preload_urls"]
            )

        # Register ALL native modules in the legacy loader so that
        # require() works for both same-bundle legacy modules and
        # dynamically-loaded lazy bundles (e.g. web_tour.automatic).
        # Include @odoo/owl explicitly so legacy odoo.define() code
        # (e.g. spreadsheet) can require() it — OWL is loaded via
        # import map, not as a native module in the bundle.
        bridge_specifiers = sorted(
            set(native_data["import_map"]) | set(self._ODOO_EXTERNAL_LIBS)
        )
        if bridge_specifiers and not _already_has_esm:
            shim_js = self._build_loader_shim_js()
            pre_nodes.append(("script", {"text": shim_js}))

        # Bridge code is ALWAYS generated (even when the import map and
        # shim were already rendered by a previous bundle on this page).
        # This registers native modules and test factories for Hoot.
        if bridge_specifiers:
            bridge_code = ""

            # Tour files (``/tests/tours/*.js``) auto-register into the
            # legacy ``web_tour.tours`` registry at module load — they
            # must be eagerly imported so the registration side-effect
            # runs.  Hoot tests (``.test.js`` files, or anything in
            # ``/tests/`` outside ``/tours/``) are wrapped in
            # ``describe()`` blocks and must be loaded through Hoot's
            # runner instead, so they are excluded from eager imports.
            hoot_specs = [
                s for s in bridge_specifiers if self._is_hoot_test_specifier(s)
            ]
            non_hoot_specs = [s for s in bridge_specifiers if s not in hoot_specs]

            if not _already_has_esm:
                # Primary bundle: eagerly import and register every
                # non-Hoot module (sources + tour files) under their
                # specifiers in ``odoo.loader.modules``.
                import_lines = []
                register_entries = []
                for i, specifier in enumerate(non_hoot_specs):
                    var = f"__m{i}"
                    # json.dumps quotes/escapes the specifier so a quote or
                    # backslash in a (developer-controlled) module path
                    # cannot break out of the string literal — same
                    # treatment the registration keys below already get.
                    import_lines.append(
                        f"import * as {var} from {json_mod.dumps(specifier)};"
                    )
                    register_entries.append(f"  {json_mod.dumps(specifier)}: {var}")
                bridge_code = "\n".join(import_lines) + "\n"
                bridge_code += "odoo.loader.registerNativeModules({\n"
                bridge_code += ",\n".join(register_entries)
                bridge_code += "\n});\n"
            else:
                # Secondary bundle: source modules are already loaded
                # by the primary bundle's esbuild output, so skip
                # generic eager imports.  Tour files, however, are
                # specific to test bundles and the parent does not
                # know about them — eager-import them here for their
                # registration side-effect.
                tour_specs = [s for s in non_hoot_specs if "/tours/" in s]
                if tour_specs:
                    bridge_code = (
                        "\n".join(f"import {json_mod.dumps(s)};" for s in tour_specs)
                        + "\n"
                    )

            # ESM native test loading: import all Hoot test files
            # eagerly via start.hoot's loadAndStart(), following Hoot's
            # canonical pattern (import all → start()).  No factories
            # needed.
            start_hoot = [s for s in hoot_specs if s.endswith("/start.hoot")]
            other_tests = [s for s in hoot_specs if s not in start_hoot]
            if start_hoot and other_tests:
                specifier_list = ",\n".join(
                    f"  {json_mod.dumps(s)}" for s in other_tests
                )
                bridge_code += (
                    f"const {{loadAndStart}} = await import({json_mod.dumps(start_hoot[0])});\n"
                    f"loadAndStart([\n{specifier_list}\n]);\n"
                )

            if bridge_code.strip():
                post_nodes.append(
                    (
                        "script",
                        {
                            "type": "module",
                            "data-bridge": bundle,
                            "text": bridge_code,
                        },
                    )
                )

        # ESM template module — inline in debug mode.
        # Secondary bundles use use_import=False so that templates
        # access @web/core/templates via odoo.loader.modules.get()
        # instead of import — the data: URI bridge may not export all
        # names (e.g. checkPrimaryTemplateParents).
        esm_tpl = asset_bundle.generate_esm_template_bundle(
            use_import=not _already_has_esm,
        )
        if esm_tpl:
            post_nodes.append(
                (
                    "script",
                    {
                        "type": "module",
                        "data-templates": bundle,
                        "text": esm_tpl,
                    },
                )
            )

        _n_bridges = sum(
            1 for v in import_map.values() if v.startswith("/web/assets/esm/bridges/")
        )
        _n_data_uri = sum(1 for v in import_map.values() if v.startswith("data:"))
        _n_real_url = len(import_map) - _n_bridges - _n_data_uri
        log_event(
            _esm_log,
            logging.DEBUG,
            "render",
            bundle=bundle,
            branch="debug",
            pre=len(pre_nodes),
            post=len(post_nodes),
            importmap=len(import_map),
            url=_n_real_url,
            bridges=_n_bridges,
            data=_n_data_uri,
            bridge_shims=len(resolved_bridges),
            already_has_esm=bool(_already_has_esm),
        )
        return pre_nodes, post_nodes

    def _save_esm_attachment(
        self,
        bundle: str,
        content: str,
        metafile: str | None = None,
        sourcemap: str | None = None,
    ) -> str:
        """Save esbuild output as an ir.attachment, return its URL.

        ``metafile`` / ``sourcemap`` are the esbuild build's sibling
        artifacts, passed only by the main-bundle save; they are ``None``
        for the separately-generated ``.templates.esm.js`` saves, which
        carry no metafile or source map.

        The URL is **content-addressable**: the hash segment is derived
        from the bundle bytes themselves, not from the source files'
        mtimes.  Two builds that produce byte-identical output share one
        attachment, and editing a source file in a way that doesn't
        change the emitted bundle (whitespace, reordered imports that
        esbuild normalizes) does NOT invalidate the browser cache.

        The ``/web/assets/esm/`` path prefix distinguishes content-hashed
        ESM bundles from the legacy ``/web/assets/{version}/`` layout
        used for concatenated ``.min.js`` bundles; the stale-version
        glob below matches both. Superseded rows are NOT deleted here —
        deletion is deferred to ``IrAttachment._gc_esm_assets`` after a
        grace window; this method only triggers the assets-cache clear
        that version propagation requires.
        """
        IrAttachment = self.env["ir.attachment"]
        content_bytes = content.encode("utf-8")
        # 16 hex chars = 64 bits of entropy, far beyond the birthday
        # bound for a single tenant's bundle corpus (~50 bundles).
        content_hash = hashlib.sha256(content_bytes).hexdigest()[:16]
        url = f"/web/assets/esm/{content_hash}/{bundle}.esm.js"

        # Check if attachment already exists
        existing = IrAttachment.sudo().search(
            [("url", "=", url), ("public", "=", True)],
            limit=1,
        )
        if existing:
            # Hit rate should be ~100% after warm-up — logged at DEBUG
            # because it's the common case, not newsworthy.
            log_event(
                _attach_log,
                logging.DEBUG,
                "reuse",
                bundle=bundle,
                url=url,
                bytes=len(content_bytes),
            )
            # Touch the row so the asset GC sees a REUSED artifact as
            # live.  Content-addressing means a reverted deploy (content
            # A → B → back to A) reuses A's original row, whose
            # ``write_date`` (and id) are older than B's — without the
            # touch, ``_gc_esm_assets``'s newest-per-name heuristic
            # treats B as the live version and sweeps A while every
            # cached node still embeds A's URL (hard 404; the ESM serve
            # path has no rebuild).  Best-effort, out-of-band commit —
            # same rationale as the create below.
            self._persist_esm_attachment_rows(
                [],
                touch_ids=existing.ids,
                bundle=bundle,
            )
            return url

        self._persist_esm_attachment_rows(
            [
                {
                    "name": f"{bundle}.esm.js",
                    "mimetype": "text/javascript",
                    "res_model": "ir.ui.view",
                    "res_id": False,
                    "type": "binary",
                    "public": True,
                    "raw": content_bytes,
                    "url": url,
                }
            ],
            bundle=bundle,
        )
        # Clean old versions across both the legacy per-version URL
        # layout (``/web/assets/<ver>/<bundle>.esm.js``) and the
        # content-addressable layout (``/web/assets/esm/<hash>/…``).
        # ``=like`` patterns are approximate: ``_`` is a single-char
        # wildcard (bundle names are full of literal underscores) and the
        # leading ``%`` can span path segments, so the sweep CAN over-match
        # sibling bundle names.  Contained by design — matches are only
        # deferred to ``_gc_esm_assets``, which re-derives liveness itself;
        # the cost of a false positive is an extra cache clear, never a
        # deleted live row.
        # Sweep matching ``.meta.json`` and ``.esm.js.map`` siblings
        # too — otherwise old hashes leave orphan rows that pile up
        # in ``ir.attachment`` and waste filestore bytes (one stale
        # 1MB metafile or 3MB sourcemap per rebuild adds up fast on
        # busy dev DBs).
        stale = IrAttachment.sudo().search(
            [
                "|",
                "|",
                "|",
                "|",
                "|",
                ("url", "=like", f"/web/assets/esm/%/{bundle}.esm.js"),
                ("url", "=like", f"/web/assets/%/{bundle}.esm.js"),
                ("url", "=like", f"/web/assets/esm/%/{bundle}.esm.js.map"),
                ("url", "=like", f"/web/assets/esm/%/{bundle}.meta.json"),
                ("url", "=like", f"/web/assets/%/{bundle}.esm.js.map"),
                ("url", "=like", f"/web/assets/%/{bundle}.meta.json"),
                ("url", "!=", url),
                ("public", "=", True),
            ]
        )
        if stale:
            # Deletion is DEFERRED to IrAttachment._gc_esm_assets: the
            # superseded rows must keep serving in-flight pages, stale CDN
            # HTML and workers that have not yet processed the cache-clear
            # signal (the ESM serve path has no on-the-fly rebuild, so a
            # deleted row is a hard 404 there). The cache clear itself —
            # previously a side effect of stale.unlink() — must still
            # happen so every worker re-renders its nodes with the new
            # version's URL.
            self.env.registry.clear_cache("assets")
            log_event(
                _attach_log,
                logging.INFO,
                "stale_deferred",
                bundle=bundle,
                count=len(stale),
            )
        log_event(
            _attach_log,
            logging.INFO,
            "save",
            bundle=bundle,
            url=url,
            bytes=len(content_bytes),
        )

        # Sibling metafile attachment (esbuild bundle analysis). ``metafile``
        # is supplied only by the main-bundle save; it is ``None`` for the
        # ``.templates.esm.js`` saves (a different code path with no metafile),
        # so the sidecar is skipped there.
        if metafile and url.endswith(".esm.js"):
            meta_url = url[: -len(".esm.js")] + ".meta.json"
            self._save_esm_sidecar(
                bundle,
                meta_url,
                metafile.encode("utf-8"),
                mimetype="application/json",
            )
        # Source-map sidecar — esbuild's ``--sourcemap=external`` mode
        # appends ``//# sourceMappingURL=<basename>.map`` to the
        # bundle, so the browser fetches this attachment URL ONLY when
        # devtools is open (zero runtime cost otherwise).  Same
        # ``.esm.js`` -> ``.esm.js.map`` filename relationship esbuild
        # picks by default, so the comment in the bundle resolves
        # correctly relative to the bundle URL.
        if sourcemap and url.endswith(".esm.js"):
            sm_url = url + ".map"
            self._save_esm_sidecar(
                bundle,
                sm_url,
                sourcemap.encode("utf-8"),
                mimetype="application/json",
            )
        return url

    def _save_esm_sidecar(
        self,
        bundle: str,
        url: str,
        content: bytes,
        mimetype: str,
    ) -> None:
        """Persist a sibling file next to an ESM bundle attachment.

        Used for metafiles today; extensible to source maps or other
        analysis side-channels.  Idempotent: reuses the existing
        attachment when the URL already maps to one.
        """
        IrAttachment = self.env["ir.attachment"]
        existing = IrAttachment.sudo().search(
            [
                ("url", "=", url),
                ("public", "=", True),
            ],
            limit=1,
        )
        if existing:
            log_event(
                _attach_log,
                logging.DEBUG,
                "sidecar_reuse",
                bundle=bundle,
                url=url,
            )
            # Same GC-liveness touch as the main-bundle reuse branch:
            # a reused sidecar must not look older than a superseded
            # sibling of the same name.
            self._persist_esm_attachment_rows(
                [],
                touch_ids=existing.ids,
                bundle=bundle,
            )
            return
        self._persist_esm_attachment_rows(
            [
                {
                    "name": url.rsplit("/", 1)[-1],
                    "mimetype": mimetype,
                    "res_model": "ir.ui.view",
                    "res_id": False,
                    "type": "binary",
                    "public": True,
                    "raw": content,
                    "url": url,
                }
            ],
            bundle=bundle,
        )
        log_event(
            _attach_log,
            logging.INFO,
            "sidecar_save",
            bundle=bundle,
            url=url,
            bytes=len(content),
        )

    def _persist_esm_attachment_rows(
        self,
        vals_list: list[dict],
        touch_ids: Sequence[int] = (),
        bundle: str = "",
    ) -> None:
        """Persist ESM asset attachments through a dedicated RW cursor.

        The rendered nodes embedding these attachment URLs are stored in
        the process-memory ``assets`` ormcache the moment the enclosing
        cached method returns — and ormcache entries never roll back with
        the transaction.  Creating the rows on the REQUEST cursor meant a
        later failure in the same request (access error in another
        template section, serialization abort) rolled the attachment back
        while the cache kept serving its URL: a hard 404 with no rebuild
        path, since the ESM serve route deliberately has none (see
        ``ir.attachment.unlink``).  A dedicated cursor that commits
        independently of the render closes that window — the same
        invariant, and the same escalation pattern,
        ``BridgeShimManager._persist_bridges_via_rw_cursor`` applies to
        bridge shims.  It also lets read-only replica renders (e.g. the
        ``/web/bundle`` lazy-load route) persist without relying on the
        http layer's whole-request read-write retry.

        Test mode writes on the request cursor instead (the
        pre-refactor behavior): rollback-safety is meaningless inside a
        test transaction, and while an HttpCase's registry cursor is a
        TestCursor sharing the test transaction, a plain
        TransactionCase's ``registry.cursor()`` opens a REAL cursor
        whose out-of-band commit is invisible to the test's snapshot
        and leaks rows past the test rollback.

        The attachments are content-addressed and idempotent, so the
        out-of-band commit is safe; a concurrent worker doing the same
        produces a harmless duplicate row (served via ``limit 1``,
        cleaned by the GC).

        :param vals_list: ``ir.attachment`` create values.  When the RW
            cursor is unreachable (primary down), falls back to creating
            on the request cursor — the pre-refactor behavior — and lets
            any error propagate so a URL is never returned (and cached)
            without a surviving row.
        :param touch_ids: existing attachment ids whose ``write_date``
            must be bumped so ``_gc_esm_assets`` keeps treating a REUSED
            content-addressed row as live (content reverts re-use old
            rows; see the reuse branches of the two savers).  Best-effort:
            a failed touch only shortens GC protection, never the render.
        """
        if _module.current_test:
            if vals_list:
                if self.env.cr.readonly:
                    # Raise WITHOUT executing the doomed INSERT: a failed
                    # statement aborts the transaction and would poison
                    # every later query of the render.  Same type the
                    # INSERT itself would raise, so callers that let it
                    # propagate (the /web/bundle payload path) still get
                    # the http layer's read-write retry.
                    raise ReadOnlySqlTransaction(
                        "cannot persist ESM attachments on a read-only "
                        "test cursor"
                    )
                self.env["ir.attachment"].with_user(SUPERUSER_ID).create(vals_list)
            # The touch is best-effort everywhere — skip it on readonly
            # test cursors (pre-refactor reuse did no write at all).
            if touch_ids and not self.env.cr.readonly:
                self.env.cr.execute(
                    "UPDATE ir_attachment SET write_date = now() at time zone 'UTC'"
                    " WHERE id = ANY(%s)",
                    (list(touch_ids),),
                )
                self.env["ir.attachment"].browse(list(touch_ids)).invalidate_recordset(
                    ["write_date"],
                )
            return
        try:
            with self.env.registry.cursor(readonly=False) as rw_cr:
                if vals_list:
                    rw_env = api.Environment(rw_cr, SUPERUSER_ID, {})
                    rw_env["ir.attachment"].create(vals_list)
                if touch_ids:
                    rw_cr.execute(
                        "UPDATE ir_attachment SET write_date = now() at time zone 'UTC'"
                        " WHERE id = ANY(%s)",
                        (list(touch_ids),),
                    )
        except Exception:
            if not vals_list:
                # Touch-only call: losing the write_date bump is harmless
                # (GC protection just isn't extended this render).
                log_event(
                    _attach_log,
                    logging.DEBUG,
                    "touch_failed",
                    bundle=bundle,
                    ids=len(touch_ids),
                )
                return
            # No writable registry cursor reachable — degrade to the
            # request cursor (pre-refactor path).  A failure here
            # propagates: better to fail the render than to cache a URL
            # whose row may not survive the transaction.
            _logger.warning(
                "ESM attachment escalation to a read-write cursor failed; "
                "creating on the request cursor",
                exc_info=True,
            )
            if self.env.cr.readonly:
                # Raise without executing the doomed INSERT (see the
                # test-mode branch above): keeps the request transaction
                # usable for callers that catch this and inline instead.
                raise ReadOnlySqlTransaction(
                    "no writable cursor reachable for ESM attachments"
                ) from None
            self.env["ir.attachment"].with_user(SUPERUSER_ID).create(vals_list)

    def _get_asset_link_urls(self, bundle: str, debug: str | bool = False) -> list[str]:
        asset_nodes = self._get_asset_nodes(bundle, js=False, debug=debug)
        return [node[1]["href"] for node in asset_nodes if node[0] == "link"]

    def _pregenerate_assets_bundles(self) -> list[str]:
        """Pregenerate all assets that may be used in web pages to speed up first loading.
        Mainly useful for tests.

        Looks for all ``t-call-assets`` in views to build the minimal set of
        bundles. Only generates assets without extras, ignoring rtl.
        """
        _logger.runbot("Pregenerating assets bundles")

        js_bundles, css_bundles = self._get_bundles_to_pregenarate()

        links = []
        start = time.time()
        for bundle in sorted(js_bundles):
            links += self._get_asset_bundle(bundle, css=False, js=True).js()
        _logger.info("JS Assets bundles generated in %s seconds", time.time() - start)
        start = time.time()
        for bundle in sorted(css_bundles):
            links += self._get_asset_bundle(bundle, css=True, js=False).css()
        _logger.info("CSS Assets bundles generated in %s seconds", time.time() - start)
        return links

    def _get_bundles_to_pregenarate(self) -> tuple[set[str], set[str]]:
        """
        Returns the list of bundles to pregenerate.
        """

        views = self.env["ir.ui.view"].search(
            [("type", "=", "qweb"), ("arch_db", "like", "t-call-assets")]
        )
        js_bundles = set()
        css_bundles = set()
        for view in views:
            for call_asset in etree.fromstring(view.arch_db).xpath(
                "//*[@t-call-assets]"
            ):
                asset = call_asset.get("t-call-assets")
                js = str2bool(call_asset.get("t-js", "True"))
                css = str2bool(call_asset.get("t-css", "True"))
                if js:
                    js_bundles.add(asset)
                if css:
                    css_bundles.add(asset)
        return (js_bundles, css_bundles)


def render(
    template_name: str | int, values: dict[str, Any], load: Any, **options: Any
) -> Markup:
    """Rendering of a qweb template without database and outside the registry.
    (Widget, field, or asset rendering is not implemented.)
    :param (string|int) template_name: template identifier
    :param dict values: template values to be used for rendering
    :param def load: function like `load(template_name)` which returns an etree
        from the given template name (from initial rendering or template
        `t-call`).
    :param options: used to compile the template
    :return: the rendered template, markup-safe
    :rtype: markupsafe.Markup
    """

    class MockPool:
        db_name = None
        _Registry__caches = {
            cache_name: LRU(cache_size)
            for cache_name, cache_size in _REGISTRY_CACHES.items()
        }
        _Registry__caches_groups = _group_caches_by_prefix(_Registry__caches)

    class MockIrQWeb(IrQweb):
        _register = False  # not visible in real registry

        pool = MockPool()

        def _get_template_info(self, id_or_xmlid: int | str) -> dict[str, Any]:
            return defaultdict(lambda: None, id=id_or_xmlid)

        def _preload_trees(
            self, refs: Sequence[int | str]
        ) -> dict[int | str, dict[str, Any]]:
            values = {}
            for ref in refs:
                tree, vid = self.env.context["load"](ref)
                values[ref] = values[vid] = {
                    "tree": tree,
                    "template": etree.tostring(tree, encoding="unicode"),
                    "xmlid": vid,
                    "ref": None,
                }
            return values

        def _load(
            self, ref: str | int
        ) -> tuple[etree._Element | str, str | int | None]:
            """
            Load the template referenced by ``ref``.

            :returns: The loaded template (as string or etree) and its
                identifier
            :rtype: tuple[etree | str, str | int | None]
            """
            return self.env.context["load"](ref)

        def _prepare_environment(self, values: dict[str, Any]) -> Self:
            values["true"] = True
            values["false"] = False
            return self.with_context(__qweb_loaded_functions={})

        def _get_field(self, *args: Any) -> None:
            msg = "Fields are not allowed in this rendering mode. Please use \"env['ir.qweb']._render\" method"
            raise NotImplementedError(msg)

        def _get_widget(self, *args: Any) -> None:
            msg = "Widgets are not allowed in this rendering mode. Please use \"env['ir.qweb']._render\" method"
            raise NotImplementedError(msg)

        def _get_asset_nodes(self, *args: Any) -> None:
            msg = "Assets are not allowed in this rendering mode. Please use \"env['ir.qweb']._render\" method"
            raise NotImplementedError(msg)

    class MockCr:
        def __init__(self) -> None:
            self.cache: dict[str, Any] = {}

    class MockEnv(dict):
        def __init__(self) -> None:
            super().__init__()
            self.context: dict[str, Any] = {}
            self.cr = MockCr()

        def __call__(
            self,
            cr: Any = None,
            user: Any = None,
            context: dict[str, Any] | None = None,
            su: Any = None,
        ) -> MockEnv:
            """Return a mocked environment, updating it with the given context.
            Allows using `ir_qweb.with_context` with sandboxed qweb.
            """
            env = MockEnv()
            env.context.update(self.context if context is None else context)
            return env

    renderer = MockIrQWeb(MockEnv(), (), ())
    return renderer._render(
        template_name, values, load=load, minimal_qcontext=True, **options
    )
